import { DerivedStats } from '../models/Stats';
import { DERIVED_CONFIG } from '../config/derived-stats-config';

export interface CombatResult {
  isHit: boolean;
  isCrit: boolean;
  damage: number;
  hitChance: number;
}

// Standard target for DPS measurement (Average mid-game enemy)
const STANDARD_DEFENSE = 150;
const STANDARD_EVASION = 50;

/**
 * Optimized combat result calculation.
 */
export const calculateCombatResult = (
  attacker: DerivedStats,
  defender: DerivedStats,
  type: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'
): CombatResult => {
  const acc = attacker.accuracy;
  const eva = defender.evasion;
  const rawHitChance = (acc / (acc + eva * 0.7)) * 100;
  // Clamped to 90-100% range to ensure elite combat efficiency
  const hitChance = rawHitChance > 100 ? 100 : (rawHitChance < 90 ? 90 : rawHitChance);

  if (Math.random() * 100 > hitChance) {
    return { isHit: false, isCrit: false, damage: 0, hitChance };
  }

  const isCrit = Math.random() * 100 <= attacker.critChance;
  const critMult = isCrit ? attacker.critDamage * 0.01 : 1.0;

  const baseAtk = type === 'PHYSICAL' ? attacker.physicalAttack : attacker.magicalAttack;
  const reduction = type === 'PHYSICAL' ? defender.physicalReduction : defender.magicalReduction;

  const baseDamage = baseAtk * (1 - reduction);
  const damage = Math.max(1, Math.round(baseDamage * critMult));

  return { isHit: true, isCrit, damage, hitChance };
};

/**
 * High-performance lightweight combat calculation for bulk simulations.
 * Minimizes object creation and property access overhead.
 */
export const calculateFastDmg = (
  atkValue: number,
  reduction: number,
  critChance: number,
  critDamage: number,
  hitChance: number
): number => {
  if (Math.random() * 100 > hitChance) return 0;
  const isCrit = Math.random() * 100 <= critChance;
  const dmg = atkValue * (1 - reduction) * (isCrit ? critDamage * 0.01 : 1.0);
  return dmg < 1 ? 1 : dmg;
};

/**
 * Calculates theoretical Expected Damage Per Second (DPS) against a standard target.
 */
export const calculateExpectedDPS = (stats: DerivedStats, attackType: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'): number => {
    const critBonusMult = (stats.critChance * 0.01) * ((stats.critDamage * 0.01) - 1);
    const avgDmgMult = 1 + critBonusMult;

    const reduction = STANDARD_DEFENSE / (STANDARD_DEFENSE + 150);
    const rawAtk = attackType === 'PHYSICAL' ? stats.physicalAttack : stats.magicalAttack;
    const baseDmg = rawAtk * (1 - reduction);
    const expectedDmgPerHit = baseDmg * avgDmgMult;

    const rawHitChance = (stats.accuracy / (stats.accuracy + STANDARD_EVASION * 0.7)) * 100;
    const hitChance = (rawHitChance > 100 ? 100 : (rawHitChance < 90 ? 90 : rawHitChance)) * 0.01;

    const actionsPerSecond = (stats.speed * 0.001) * 25;

    return Math.round(expectedDmgPerHit * hitChance * actionsPerSecond);
};

/**
 * Calculates overall Combat Power (CP).
 */
export const calculateCombatPower = (stats: DerivedStats, attackType: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'): number => {
    const dps = calculateExpectedDPS(stats, attackType);
    const offensiveScore = dps * 12;

    const avgReduction = (stats.physicalReduction + stats.magicalReduction) * 0.5;
    const effectiveHp = stats.maxHp / Math.max(0.1, (1 - avgReduction));

    const evasionBonus = 1 + (stats.evasion * 0.005);
    const defensiveScore = (effectiveHp * evasionBonus) * 0.25;

    return Math.round((offensiveScore + defensiveScore) * 0.1);
};

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { useGame } from '../context/GameContext';
import { Mercenary } from '../models/Mercenary';
import { calculateDerivedStats, applyEquipmentBonuses, DerivedStats, mergePrimaryStats, PrimaryStats } from '../models/Stats';
import { Equipment } from '../models/Equipment';
import { calculateCombatResult, calculateExpectedDPS, calculateFastDmg } from '../utils/combatLogic';

const ACTION_THRESHOLD = 1000;
const MAX_SQUAD_SIZE = 4;

export interface CombatantInstance {
    instanceId: string;
    mercenaryId: string | null;
    level: number;
    allocatedStats: PrimaryStats;
    currentHp: number;
    gauge: number;
    dps: number;
    lastAttacker?: boolean;
    lastDamaged?: boolean;
    // Stats for MVP and performance tracking
    kills: number;
    damageDealt: number;
    damageTaken: number;
}

export interface MatchStats {
    totalDmg: number;
    crits: number;
    misses: number;
    attacks: number;
    evasions: number;
    maxDmg: number;
    minDmg: number;
}

export interface CombatLogEntry {
    msg: string;
    team: 'A' | 'B' | 'SYSTEM';
    isCrit?: boolean;
    isMiss?: boolean;
}

export interface SingleMatchReport {
    winner: 'A' | 'B' | null;
    durationTicks: number;
    statsA: MatchStats;
    statsB: MatchStats;
    analysis: string[];
}

export interface BulkReport {
    rounds: number;
    winA: number;
    winB: number;
    avgAtksA: number;
    avgAtksB: number;
    avgCritsA: number;
    avgCritsB: number;
    avgEvasionsA: number;
    avgEvasionsB: number;
}

export interface SimulationHook {
    teamA: CombatantInstance[];
    teamB: CombatantInstance[];
    addSlot: (side: 'A' | 'B') => void;
    removeSlot: (side: 'A' | 'B', instanceId: string) => void;
    updateSlot: (side: 'A' | 'B', instanceId: string, data: Partial<CombatantInstance>) => void;
    combatLog: CombatLogEntry[];
    clearLogs: () => void;
    isBattleRunning: boolean;
    battleSpeed: 1 | 2 | 5 | 10;
    setBattleSpeed: (speed: 1 | 2 | 5 | 10) => void;
    singleMatchReport: SingleMatchReport | null;
    liveStats: { A: MatchStats, B: MatchStats } | null;
    bulkReport: BulkReport | null;
    isSearching: boolean;
    handleReset: () => void;
    runBulkSimulation: () => void;
    runAttackCycle: () => void;
    getDerivedStats: (mercId: string | null, level: number, alloc: PrimaryStats) => DerivedStats | null;
}

const createEmptyCombatant = (): CombatantInstance => ({
    instanceId: `inst_${Math.random().toString(36).substr(2, 9)}`,
    mercenaryId: null,
    level: 1,
    allocatedStats: { str: 0, vit: 0, dex: 0, int: 0, luk: 0 },
    currentHp: 0,
    gauge: 0,
    dps: 0,
    kills: 0,
    damageDealt: 0,
    damageTaken: 0
});

const createInitialStats = (): MatchStats => ({
    totalDmg: 0, crits: 0, misses: 0, attacks: 0, evasions: 0, maxDmg: 0, minDmg: 0
});

export const useSimulation = (): SimulationHook => {
    const { state } = useGame();

    const [battleState, setBattleState] = useState<{
        teamA: CombatantInstance[],
        teamB: CombatantInstance[]
    }>({
        teamA: [createEmptyCombatant()],
        teamB: [createEmptyCombatant()]
    });

    const [combatLog, setCombatLog] = useState<CombatLogEntry[]>([]);
    const [isBattleRunning, setIsBattleRunning] = useState(false);
    const [battleSpeed, setBattleSpeed] = useState<1 | 2 | 5 | 10>(1);
    const [singleMatchReport, setSingleMatchReport] = useState<SingleMatchReport | null>(null);
    const [liveStats, setLiveStats] = useState<{ A: MatchStats, B: MatchStats } | null>(null);
    const [bulkReport, setBulkReport] = useState<BulkReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);
    const battleSpeedRef = useRef<number>(1);
    const stopSearchRef = useRef(false);

    const matchStatsRef = useRef<{A: MatchStats, B: MatchStats, ticks: number}>({
        A: createInitialStats(),
        B: createInitialStats(),
        ticks: 0
    });

    const statsCache = useRef<Map<string, { key: string, stats: DerivedStats }>>(new Map());

    useEffect(() => { battleSpeedRef.current = battleSpeed; }, [battleSpeed]);

    const getDerivedStats = useCallback((mercId: string | null, level: number, alloc: PrimaryStats) => {
        if (!mercId) return null;

        const merc = state.knownMercenaries.find(m => m.id === mercId);
        if (!merc) return null;

        const cacheKey = `${mercId}_${level}_${alloc.str}_${alloc.vit}_${alloc.dex}_${alloc.int}_${alloc.luk}`;
        const cached = statsCache.current.get(mercId);
        if (cached && cached.key === cacheKey) return cached.stats;

        const primary = mergePrimaryStats(merc.stats, alloc);
        const base = calculateDerivedStats(primary, level);
        const eqStats = (Object.values(merc.equipment) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean);
        const stats = applyEquipmentBonuses(base, eqStats as any);

        statsCache.current.set(mercId, { key: cacheKey, stats });
        return stats;
    }, [state.knownMercenaries]);

    useEffect(() => {
        if (isBattleRunning) return;
        const refreshTeam = (team: CombatantInstance[]) => team.map(c => {
            if (!c.mercenaryId) return c;
            const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
            if (!derived) return c;
            const isMage = derived.magicalAttack > derived.physicalAttack;
            return { ...c, dps: calculateExpectedDPS(derived, isMage ? 'MAGICAL' : 'PHYSICAL') };
        });

        setBattleState(prev => ({
            teamA: refreshTeam(prev.teamA),
            teamB: refreshTeam(prev.teamB)
        }));
    }, [state.knownMercenaries, getDerivedStats, isBattleRunning]);

    const addSlot = (side: 'A' | 'B') => {
        setBattleState(prev => {
            const teamKey = side === 'A' ? 'teamA' : 'teamB';
            if (prev[teamKey].length >= MAX_SQUAD_SIZE) return prev;
            return { ...prev, [teamKey]: [...prev[teamKey], createEmptyCombatant()] };
        });
    };

    const removeSlot = (side: 'A' | 'B', instanceId: string) => {
        setBattleState(prev => {
            const teamKey = side === 'A' ? 'teamA' : 'teamB';
            return { ...prev, [teamKey]: prev[teamKey].filter(i => i.instanceId !== instanceId) };
        });
    };

    const updateSlot = (side: 'A' | 'B', instanceId: string, data: Partial<CombatantInstance>) => {
        setBattleState(prev => {
            const teamKey = side === 'A' ? 'teamA' : 'teamB';
            const newTeam = prev[teamKey].map(item => {
                if (item.instanceId !== instanceId) return item;
                let updated = { ...item, ...data };

                if (data.mercenaryId !== undefined && data.mercenaryId !== null) {
                    const merc = state.knownMercenaries.find(m => m.id === data.mercenaryId);
                    if (merc) {
                        updated.level = merc.level;
                        updated.allocatedStats = { ...merc.allocatedStats };
                    }
                }

                if (data.mercenaryId !== undefined || data.level !== undefined || data.allocatedStats !== undefined) {
                    const derived = getDerivedStats(updated.mercenaryId, updated.level, updated.allocatedStats);
                    if (derived) {
                        updated.currentHp = derived.maxHp;
                        const isMage = derived.magicalAttack > derived.physicalAttack;
                        updated.dps = calculateExpectedDPS(derived, isMage ? 'MAGICAL' : 'PHYSICAL');
                    }
                }
                return updated;
            });
            return { ...prev, [teamKey]: newTeam };
        });
    };

    const addLog = (msg: string, team: 'A' | 'B' | 'SYSTEM' = 'SYSTEM', isCrit = false, isMiss = false) => {
        setCombatLog(prev => [...prev, { msg, team, isCrit, isMiss }].slice(-100));
    };

    const clearLogs = useCallback(() => {
        setCombatLog([]);
    }, []);

    const handleReset = useCallback(() => {
        setIsBattleRunning(false); setIsSearching(false); stopSearchRef.current = true;
        if (battleInterval.current) clearInterval(battleInterval.current);

        const resetTeam = (team: CombatantInstance[]) => team.map(c => {
            if (!c.mercenaryId) return c;
            const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
            return { ...c, currentHp: derived ? derived.maxHp : 0, gauge: 0, lastAttacker: false, lastDamaged: false, kills: 0, damageDealt: 0, damageTaken: 0 };
        });

        setBattleState(prev => ({ teamA: resetTeam(prev.teamA), teamB: resetTeam(prev.teamB) }));
        setCombatLog([]);
        setSingleMatchReport(null); setBulkReport(null); setLiveStats(null);
        matchStatsRef.current = { A: createInitialStats(), B: createInitialStats(), ticks: 0 };
    }, [getDerivedStats]);

    const runBulkSimulation = () => {
        if (isSearching) return;
        setBulkReport(null);
        const rounds = 10000;
        let winA = 0;
        let totalAtksA = 0, totalAtksB = 0;
        let totalCritsA = 0, totalCritsB = 0;
        let totalEvasionsA = 0, totalEvasionsB = 0;

        const teamAData = battleState.teamA.filter(c => c.mercenaryId).map(c => {
            const d = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!;
            const isMage = d.magicalAttack > d.physicalAttack;
            return { hp: d.maxHp, spd: d.speed, atk: isMage ? d.magicalAttack : d.physicalAttack, red: isMage ? d.magicalReduction : d.physicalReduction, crt: d.critChance, cdmg: d.critDamage };
        });
        const teamBData = battleState.teamB.filter(c => c.mercenaryId).map(c => {
            const d = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!;
            const isMage = d.magicalAttack > d.physicalAttack;
            return { hp: d.maxHp, spd: d.speed, atk: isMage ? d.magicalAttack : d.physicalAttack, red: isMage ? d.magicalReduction : d.physicalReduction, crt: d.critChance, cdmg: d.critDamage };
        });

        if (teamAData.length === 0 || teamBData.length === 0) return;

        for (let i = 0; i < rounds; i++) {
            const hpsA = new Float32Array(teamAData.map(d => d.hp));
            const hpsB = new Float32Array(teamBData.map(d => d.hp));
            const gaugesA = new Float32Array(teamAData.length);
            const gaugesB = new Float32Array(teamBData.length);
            let aliveA = teamAData.length;
            let aliveB = teamBData.length;

            while (aliveA > 0 && aliveB > 0) {
                for (let j = 0; j < teamAData.length; j++) if (hpsA[j] > 0) gaugesA[j] += teamAData[j].spd;
                for (let j = 0; j < teamBData.length; j++) if (hpsB[j] > 0) gaugesB[j] += teamBData[j].spd;

                for (let j = 0; j < teamAData.length; j++) {
                    if (gaugesA[j] >= ACTION_THRESHOLD && hpsA[j] > 0) {
                        gaugesA[j] -= ACTION_THRESHOLD;
                        const targets = [];
                        for(let k=0; k<hpsB.length; k++) if(hpsB[k]>0) targets.push(k);
                        if(targets.length === 0) break;
                        const tIdx = targets[Math.floor(Math.random()*targets.length)];
                        totalAtksA++;
                        // Standardized hit chance for bulk analysis reflecting high efficiency
                        const dmg = calculateFastDmg(teamAData[j].atk, teamBData[tIdx].red, teamAData[j].crt, teamAData[j].cdmg, 95); 
                        if(dmg > 0) { hpsB[tIdx] -= dmg; if(hpsB[tIdx] <= 0) aliveB--; } else { totalEvasionsB++; }
                    }
                }
                if (aliveB <= 0) break;
                for (let j = 0; j < teamBData.length; j++) {
                    if (gaugesB[j] >= ACTION_THRESHOLD && hpsB[j] > 0) {
                        gaugesB[j] -= ACTION_THRESHOLD;
                        const targets = [];
                        for(let k=0; k<hpsA.length; k++) if(hpsA[k]>0) targets.push(k);
                        if(targets.length === 0) break;
                        const tIdx = targets[Math.floor(Math.random()*targets.length)];
                        totalAtksB++;
                        // Standardized hit chance for bulk analysis reflecting high efficiency
                        const dmg = calculateFastDmg(teamBData[j].atk, teamAData[tIdx].red, teamBData[j].crt, teamBData[j].cdmg, 95);
                        if(dmg > 0) { hpsA[tIdx] -= dmg; if(hpsA[tIdx] <= 0) aliveA--; } else { totalEvasionsA++; }
                    }
                }
            }
            if (aliveA > 0) winA++;
        }
        setBulkReport({ rounds, winA, winB: rounds - winA, avgAtksA: totalAtksA / rounds, avgAtksB: totalAtksB / rounds, avgCritsA: totalCritsA / rounds, avgCritsB: totalCritsB / rounds, avgEvasionsA: totalEvasionsA / rounds, avgEvasionsB: totalEvasionsB / rounds });
    };

    const runAttackCycle = () => {
        if (isBattleRunning) { 
            setIsBattleRunning(false); 
            if (battleInterval.current) clearInterval(battleInterval.current); 
            return; 
        }

        const validA = battleState.teamA.filter(c => c.mercenaryId);
        const validB = battleState.teamB.filter(c => c.mercenaryId);
        if (validA.length === 0 || validB.length === 0) return;

        setSingleMatchReport(null); 
        setBulkReport(null);
        setCombatLog([]); 
        matchStatsRef.current = { A: createInitialStats(), B: createInitialStats(), ticks: 0 };
        setLiveStats({ A: createInitialStats(), B: createInitialStats() });

        setBattleState(prev => {
            const resetTeam = (team: CombatantInstance[]) => team.map(c => {
                if (!c.mercenaryId) return c;
                const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
                return { ...c, currentHp: derived ? derived.maxHp : 0, gauge: 0, lastAttacker: false, lastDamaged: false, kills: 0, damageDealt: 0, damageTaken: 0 };
            });
            return { teamA: resetTeam(prev.teamA), teamB: resetTeam(prev.teamB) };
        });

        setIsBattleRunning(true);

        battleInterval.current = setInterval(() => {
            const speedMult = battleSpeedRef.current; 
            matchStatsRef.current.ticks++;

            setBattleState(prev => {
                const nextA = prev.teamA.map(c => {
                    return (c.mercenaryId && c.currentHp > 0) ? { ...c, gauge: c.gauge + (getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!.speed * 0.1 * speedMult) } : c;
                });
                const nextB = prev.teamB.map(c => {
                    return (c.mercenaryId && c.currentHp > 0) ? { ...c, gauge: c.gauge + (getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!.speed * 0.1 * speedMult) } : c;
                });

                const executeAttack = (att: CombatantInstance, side: 'A' | 'B') => {
                    const targets = (side === 'A' ? nextB : nextA).filter(c => c.mercenaryId && c.currentHp > 0);
                    if (targets.length === 0) return;
                    const target = targets[Math.floor(Math.random() * targets.length)];
                    const attD = getDerivedStats(att.mercenaryId, att.level, att.allocatedStats)!;
                    const defD = getDerivedStats(target.mercenaryId, target.level, target.allocatedStats)!;
                    const stats = side === 'A' ? matchStatsRef.current.A : matchStatsRef.current.B;
                    const enemyStats = side === 'A' ? matchStatsRef.current.B : matchStatsRef.current.A;

                    stats.attacks++;
                    att.gauge -= ACTION_THRESHOLD;
                    att.lastAttacker = true;

                    setTimeout(() => setBattleState(curr => ({ teamA: curr.teamA.map(c => c.instanceId === att.instanceId ? { ...c, lastAttacker: false } : c), teamB: curr.teamB.map(c => c.instanceId === att.instanceId ? { ...c, lastAttacker: false } : c) })), 120);

                    const res = calculateCombatResult(attD, defD, attD.magicalAttack > attD.physicalAttack ? 'MAGICAL' : 'PHYSICAL');
                    if (res.isHit) {
                        if (res.isCrit) stats.crits++;
                        stats.totalDmg += res.damage;
                        if (res.damage > stats.maxDmg) stats.maxDmg = res.damage;
                        if (stats.minDmg === 0 || res.damage < stats.minDmg) stats.minDmg = res.damage;

                        // Performance Stats
                        att.damageDealt += res.damage;
                        target.damageTaken += res.damage;
                        target.currentHp = Math.max(0, target.currentHp - res.damage);

                        // Kill Logic
                        if (target.currentHp <= 0) {
                            att.kills += 1;
                        }

                        // Trigger Damaged Animation
                        target.lastDamaged = true;
                        setTimeout(() => setBattleState(curr => ({ teamA: curr.teamA.map(c => c.instanceId === target.instanceId ? { ...c, lastDamaged: false } : c), teamB: curr.teamB.map(c => c.instanceId === target.instanceId ? { ...c, lastDamaged: false } : c) })), 200);

                        addLog(`${state.knownMercenaries.find(m=>m.id===att.mercenaryId)!.name} hits for ${res.damage}${res.isCrit ? "!" : ""}`, side, res.isCrit);
                    } else {
                        stats.misses++; enemyStats.evasions++;
                        addLog(`${state.knownMercenaries.find(m=>m.id===att.mercenaryId)!.name} missed!`, side, false, true);
                    }
                };

                nextA.filter(c => c.gauge >= ACTION_THRESHOLD && c.currentHp > 0).forEach(c => executeAttack(c, 'A'));
                nextB.filter(c => c.gauge >= ACTION_THRESHOLD && c.currentHp > 0).forEach(c => executeAttack(c, 'B'));

                const curA = nextA.filter(c => c.mercenaryId && c.currentHp > 0).length;
                const curB = nextB.filter(c => c.mercenaryId && c.currentHp > 0).length;

                setLiveStats({ A: { ...matchStatsRef.current.A }, B: { ...matchStatsRef.current.B } });

                if (curA === 0 || curB === 0) {
                    setIsBattleRunning(false); 
                    if (battleInterval.current) clearInterval(battleInterval.current);
                    setSingleMatchReport({ 
                        winner: curA > 0 ? 'A' : 'B', 
                        durationTicks: matchStatsRef.current.ticks, 
                        statsA: { ...matchStatsRef.current.A }, 
                        statsB: { ...matchStatsRef.current.B }, 
                        analysis: ["Battle Concluded."] 
                    });
                }
                return { teamA: nextA, teamB: nextB };
            });
        }, 40);
    };

    return {
        teamA: battleState.teamA, teamB: battleState.teamB, addSlot, removeSlot, updateSlot,
        combatLog, clearLogs, isBattleRunning, battleSpeed, setBattleSpeed,
        singleMatchReport, liveStats, bulkReport, isSearching,
        handleReset, runBulkSimulation, runAttackCycle, getDerivedStats
    };
};

import { DerivedStats } from '../models/Stats';
import { DERIVED_CONFIG } from '../config/derived-stats-config';

export interface CombatResult {
  isHit: boolean;
  isCrit: boolean;
  damage: number;
  hitChance: number;
}

// Standard target for DPS measurement (Average mid-game enemy)
const STANDARD_DEFENSE = 150;
const STANDARD_EVASION = 50;

/**
 * Optimized combat result calculation.
 */
export const calculateCombatResult = (
  attacker: DerivedStats,
  defender: DerivedStats,
  type: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'
): CombatResult => {
  const acc = attacker.accuracy;
  const eva = defender.evasion;
  const rawHitChance = (acc / (acc + eva * 0.7)) * 100;
  // Clamped to 90-100% range to ensure elite combat efficiency as requested
  const hitChance = rawHitChance > 100 ? 100 : (rawHitChance < 90 ? 90 : rawHitChance);

  if (Math.random() * 100 > hitChance) {
    return { isHit: false, isCrit: false, damage: 0, hitChance };
  }

  const isCrit = Math.random() * 100 <= attacker.critChance;
  const critMult = isCrit ? attacker.critDamage * 0.01 : 1.0;

  const baseAtk = type === 'PHYSICAL' ? attacker.physicalAttack : attacker.magicalAttack;
  const reduction = type === 'PHYSICAL' ? defender.physicalReduction : defender.magicalReduction;

  const baseDamage = baseAtk * (1 - reduction);
  const damage = Math.max(1, Math.round(baseDamage * critMult));

  return { isHit: true, isCrit, damage, hitChance };
};

/**
 * High-performance lightweight combat calculation for bulk simulations.
 * Minimizes object creation and property access overhead.
 */
export const calculateFastDmg = (
  atkValue: number,
  reduction: number,
  critChance: number,
  critDamage: number,
  hitChance: number
): number => {
  if (Math.random() * 100 > hitChance) return 0;
  const isCrit = Math.random() * 100 <= critChance;
  const dmg = atkValue * (1 - reduction) * (isCrit ? critDamage * 0.01 : 1.0);
  return dmg < 1 ? 1 : dmg;
};

/**
 * Calculates theoretical Expected Damage Per Second (DPS) against a standard target.
 */
export const calculateExpectedDPS = (stats: DerivedStats, attackType: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'): number => {
    const critBonusMult = (stats.critChance * 0.01) * ((stats.critDamage * 0.01) - 1);
    const avgDmgMult = 1 + critBonusMult;

    const reduction = STANDARD_DEFENSE / (STANDARD_DEFENSE + 150);
    const rawAtk = attackType === 'PHYSICAL' ? stats.physicalAttack : stats.magicalAttack;
    const baseDmg = rawAtk * (1 - reduction);
    const expectedDmgPerHit = baseDmg * avgDmgMult;

    const rawHitChance = (stats.accuracy / (stats.accuracy + STANDARD_EVASION * 0.7)) * 100;
    // Updated to match high efficiency range
    const hitChance = (rawHitChance > 100 ? 100 : (rawHitChance < 90 ? 90 : rawHitChance)) * 0.01;

    const actionsPerSecond = (stats.speed * 0.001) * 25;

    return Math.round(expectedDmgPerHit * hitChance * actionsPerSecond);
};

/**
 * Calculates overall Combat Power (CP).
 */
export const calculateCombatPower = (stats: DerivedStats, attackType: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'): number => {
    const dps = calculateExpectedDPS(stats, attackType);
    const offensiveScore = dps * 12;

    const avgReduction = (stats.physicalReduction + stats.magicalReduction) * 0.5;
    const effectiveHp = stats.maxHp / Math.max(0.1, (1 - avgReduction));

    const evasionBonus = 1 + (stats.evasion * 0.005);
    const defensiveScore = (effectiveHp * evasionBonus) * 0.25;

    return Math.round((offensiveScore + defensiveScore) * 0.1);
};

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { useGame } from '../context/GameContext';
import { Mercenary } from '../models/Mercenary';
import { calculateDerivedStats, applyEquipmentBonuses, DerivedStats, mergePrimaryStats, PrimaryStats } from '../models/Stats';
import { Equipment } from '../models/Equipment';
import { calculateCombatResult, calculateExpectedDPS, calculateFastDmg } from '../utils/combatLogic';

const ACTION_THRESHOLD = 1000;
const MAX_SQUAD_SIZE = 4;

export interface CombatantInstance {
    instanceId: string;
    mercenaryId: string | null;
    level: number;
    allocatedStats: PrimaryStats;
    currentHp: number;
    gauge: number;
    dps: number;
    lastAttacker?: boolean;
    lastDamaged?: boolean;
    // Stats for MVP and performance tracking
    kills: number;
    damageDealt: number;
    damageTaken: number;
}

export interface MatchStats {
    totalDmg: number;
    crits: number;
    misses: number;
    attacks: number;
    evasions: number;
    maxDmg: number;
    minDmg: number;
}

export interface CombatLogEntry {
    msg: string;
    team: 'A' | 'B' | 'SYSTEM';
    isCrit?: boolean;
    isMiss?: boolean;
}

export interface SingleMatchReport {
    winner: 'A' | 'B' | null;
    durationTicks: number;
    statsA: MatchStats;
    statsB: MatchStats;
    analysis: string[];
}

export interface BulkReport {
    rounds: number;
    winA: number;
    winB: number;
    avgAtksA: number;
    avgAtksB: number;
    avgCritsA: number;
    avgCritsB: number;
    avgEvasionsA: number;
    avgEvasionsB: number;
}

export interface SimulationHook {
    teamA: CombatantInstance[];
    teamB: CombatantInstance[];
    addSlot: (side: 'A' | 'B') => void;
    removeSlot: (side: 'A' | 'B', instanceId: string) => void;
    updateSlot: (side: 'A' | 'B', instanceId: string, data: Partial<CombatantInstance>) => void;
    combatLog: CombatLogEntry[];
    clearLogs: () => void;
    isBattleRunning: boolean;
    battleSpeed: 1 | 2 | 5 | 10;
    setBattleSpeed: (speed: 1 | 2 | 5 | 10) => void;
    singleMatchReport: SingleMatchReport | null;
    liveStats: { A: MatchStats, B: MatchStats } | null;
    bulkReport: BulkReport | null;
    isSearching: boolean;
    handleReset: () => void;
    runBulkSimulation: () => void;
    runAttackCycle: () => void;
    getDerivedStats: (mercId: string | null, level: number, alloc: PrimaryStats) => DerivedStats | null;
}

const createEmptyCombatant = (): CombatantInstance => ({
    instanceId: `inst_${Math.random().toString(36).substr(2, 9)}`,
    mercenaryId: null,
    level: 1,
    allocatedStats: { str: 0, vit: 0, dex: 0, int: 0, luk: 0 },
    currentHp: 0,
    gauge: 0,
    dps: 0,
    kills: 0,
    damageDealt: 0,
    damageTaken: 0
});

const createInitialStats = (): MatchStats => ({
    totalDmg: 0, crits: 0, misses: 0, attacks: 0, evasions: 0, maxDmg: 0, minDmg: 0
});

export const useSimulation = (): SimulationHook => {
    const { state } = useGame();

    const [battleState, setBattleState] = useState<{
        teamA: CombatantInstance[],
        teamB: CombatantInstance[]
    }>({
        teamA: [createEmptyCombatant()],
        teamB: [createEmptyCombatant()]
    });

    const [combatLog, setCombatLog] = useState<CombatLogEntry[]>([]);
    const [isBattleRunning, setIsBattleRunning] = useState(false);
    const [battleSpeed, setBattleSpeed] = useState<1 | 2 | 5 | 10>(1);
    const [singleMatchReport, setSingleMatchReport] = useState<SingleMatchReport | null>(null);
    const [liveStats, setLiveStats] = useState<{ A: MatchStats, B: MatchStats } | null>(null);
    const [bulkReport, setBulkReport] = useState<BulkReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);
    const battleSpeedRef = useRef<number>(1);
    const stopSearchRef = useRef(false);

    const matchStatsRef = useRef<{A: MatchStats, B: MatchStats, ticks: number}>({
        A: createInitialStats(),
        B: createInitialStats(),
        ticks: 0
    });

    const statsCache = useRef<Map<string, { key: string, stats: DerivedStats }>>(new Map());

    useEffect(() => { battleSpeedRef.current = battleSpeed; }, [battleSpeed]);

    const getDerivedStats = useCallback((mercId: string | null, level: number, alloc: PrimaryStats) => {
        if (!mercId) return null;

        const merc = state.knownMercenaries.find(m => m.id === mercId);
        if (!merc) return null;

        const cacheKey = `${mercId}_${level}_${alloc.str}_${alloc.vit}_${alloc.dex}_${alloc.int}_${alloc.luk}`;
        const cached = statsCache.current.get(mercId);
        if (cached && cached.key === cacheKey) return cached.stats;

        const primary = mergePrimaryStats(merc.stats, alloc);
        const base = calculateDerivedStats(primary, level);
        const eqStats = (Object.values(merc.equipment) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean);
        const stats = applyEquipmentBonuses(base, eqStats as any);

        statsCache.current.set(mercId, { key: cacheKey, stats });
        return stats;
    }, [state.knownMercenaries]);

    useEffect(() => {
        if (isBattleRunning) return;
        const refreshTeam = (team: CombatantInstance[]) => team.map(c => {
            if (!c.mercenaryId) return c;
            const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
            if (!derived) return c;
            const isMage = derived.magicalAttack > derived.physicalAttack;
            return { ...c, dps: calculateExpectedDPS(derived, isMage ? 'MAGICAL' : 'PHYSICAL') };
        });

        setBattleState(prev => ({
            teamA: refreshTeam(prev.teamA),
            teamB: refreshTeam(prev.teamB)
        }));
    }, [state.knownMercenaries, getDerivedStats, isBattleRunning]);

    const addSlot = (side: 'A' | 'B') => {
        setBattleState(prev => {
            const teamKey = side === 'A' ? 'teamA' : 'teamB';
            if (prev[teamKey].length >= MAX_SQUAD_SIZE) return prev;
            return { ...prev, [teamKey]: [...prev[teamKey], createEmptyCombatant()] };
        });
    };

    const removeSlot = (side: 'A' | 'B', instanceId: string) => {
        setBattleState(prev => {
            const teamKey = side === 'A' ? 'teamA' : 'teamB';
            return { ...prev, [teamKey]: prev[teamKey].filter(i => i.instanceId !== instanceId) };
        });
    };

    const updateSlot = (side: 'A' | 'B', instanceId: string, data: Partial<CombatantInstance>) => {
        setBattleState(prev => {
            const teamKey = side === 'A' ? 'teamA' : 'teamB';
            const newTeam = prev[teamKey].map(item => {
                if (item.instanceId !== instanceId) return item;
                let updated = { ...item, ...data };

                if (data.mercenaryId !== undefined && data.mercenaryId !== null) {
                    const merc = state.knownMercenaries.find(m => m.id === data.mercenaryId);
                    if (merc) {
                        updated.level = merc.level;
                        updated.allocatedStats = { ...merc.allocatedStats };
                    }
                }

                if (data.mercenaryId !== undefined || data.level !== undefined || data.allocatedStats !== undefined) {
                    const derived = getDerivedStats(updated.mercenaryId, updated.level, updated.allocatedStats);
                    if (derived) {
                        updated.currentHp = derived.maxHp;
                        const isMage = derived.magicalAttack > derived.physicalAttack;
                        updated.dps = calculateExpectedDPS(derived, isMage ? 'MAGICAL' : 'PHYSICAL');
                    }
                }
                return updated;
            });
            return { ...prev, [teamKey]: newTeam };
        });
    };

    const addLog = (msg: string, team: 'A' | 'B' | 'SYSTEM' = 'SYSTEM', isCrit = false, isMiss = false) => {
        setCombatLog(prev => [...prev, { msg, team, isCrit, isMiss }].slice(-100));
    };

    const clearLogs = useCallback(() => {
        setCombatLog([]);
    }, []);

    const handleReset = useCallback(() => {
        setIsBattleRunning(false); setIsSearching(false); stopSearchRef.current = true;
        if (battleInterval.current) clearInterval(battleInterval.current);

        const resetTeam = (team: CombatantInstance[]) => team.map(c => {
            if (!c.mercenaryId) return c;
            const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
            return { ...c, currentHp: derived ? derived.maxHp : 0, gauge: 0, lastAttacker: false, lastDamaged: false, kills: 0, damageDealt: 0, damageTaken: 0 };
        });

        setBattleState(prev => ({ teamA: resetTeam(prev.teamA), teamB: resetTeam(prev.teamB) }));
        setCombatLog([]);
        setSingleMatchReport(null); setBulkReport(null); setLiveStats(null);
        matchStatsRef.current = { A: createInitialStats(), B: createInitialStats(), ticks: 0 };
    }, [getDerivedStats]);

    const runBulkSimulation = () => {
        if (isSearching) return;
        setBulkReport(null);
        const rounds = 10000;
        let winA = 0;
        let totalAtksA = 0, totalAtksB = 0;
        let totalCritsA = 0, totalCritsB = 0;
        let totalEvasionsA = 0, totalEvasionsB = 0;

        const teamAData = battleState.teamA.filter(c => c.mercenaryId).map(c => {
            const d = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!;
            const isMage = d.magicalAttack > d.physicalAttack;
            return { hp: d.maxHp, spd: d.speed, atk: isMage ? d.magicalAttack : d.physicalAttack, red: isMage ? d.magicalReduction : d.physicalReduction, crt: d.critChance, cdmg: d.critDamage };
        });
        const teamBData = battleState.teamB.filter(c => c.mercenaryId).map(c => {
            const d = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!;
            const isMage = d.magicalAttack > d.physicalAttack;
            return { hp: d.maxHp, spd: d.speed, atk: isMage ? d.magicalAttack : d.physicalAttack, red: isMage ? d.magicalReduction : d.physicalReduction, crt: d.critChance, cdmg: d.critDamage };
        });

        if (teamAData.length === 0 || teamBData.length === 0) return;

        for (let i = 0; i < rounds; i++) {
            const hpsA = new Float32Array(teamAData.map(d => d.hp));
            const hpsB = new Float32Array(teamBData.map(d => d.hp));
            const gaugesA = new Float32Array(teamAData.length);
            const gaugesB = new Float32Array(teamBData.length);
            let aliveA = teamAData.length;
            let aliveB = teamBData.length;

            while (aliveA > 0 && aliveB > 0) {
                for (let j = 0; j < teamAData.length; j++) if (hpsA[j] > 0) gaugesA[j] += teamAData[j].spd;
                for (let j = 0; j < teamBData.length; j++) if (hpsB[j] > 0) gaugesB[j] += teamBData[j].spd;

                for (let j = 0; j < teamAData.length; j++) {
                    if (gaugesA[j] >= ACTION_THRESHOLD && hpsA[j] > 0) {
                        gaugesA[j] -= ACTION_THRESHOLD;
                        const targets = [];
                        for(let k=0; k<hpsB.length; k++) if(hpsB[k]>0) targets.push(k);
                        if(targets.length === 0) break;
                        const tIdx = targets[Math.floor(Math.random()*targets.length)];
                        totalAtksA++;
                        // Standardized hit chance for bulk analysis reflecting new high efficiency
                        const dmg = calculateFastDmg(teamAData[j].atk, teamBData[tIdx].red, teamAData[j].crt, teamAData[j].cdmg, 95); 
                        if(dmg > 0) { hpsB[tIdx] -= dmg; if(hpsB[tIdx] <= 0) aliveB--; } else { totalEvasionsB++; }
                    }
                }
                if (aliveB <= 0) break;
                for (let j = 0; j < teamBData.length; j++) {
                    if (gaugesB[j] >= ACTION_THRESHOLD && hpsB[j] > 0) {
                        gaugesB[j] -= ACTION_THRESHOLD;
                        const targets = [];
                        for(let k=0; k<hpsA.length; k++) if(hpsA[k]>0) targets.push(k);
                        if(targets.length === 0) break;
                        const tIdx = targets[Math.floor(Math.random()*targets.length)];
                        totalAtksB++;
                        // Standardized hit chance for bulk analysis reflecting new high efficiency
                        const dmg = calculateFastDmg(teamBData[j].atk, teamAData[tIdx].red, teamBData[j].crt, teamBData[j].cdmg, 95);
                        if(dmg > 0) { hpsA[tIdx] -= dmg; if(hpsA[tIdx] <= 0) aliveA--; } else { totalEvasionsA++; }
                    }
                }
            }
            if (aliveA > 0) winA++;
        }
        setBulkReport({ rounds, winA, winB: rounds - winA, avgAtksA: totalAtksA / rounds, avgAtksB: totalAtksB / rounds, avgCritsA: totalCritsA / rounds, avgCritsB: totalCritsB / rounds, avgEvasionsA: totalEvasionsA / rounds, avgEvasionsB: totalEvasionsB / rounds });
    };

    const runAttackCycle = () => {
        if (isBattleRunning) { 
            setIsBattleRunning(false); 
            if (battleInterval.current) clearInterval(battleInterval.current); 
            return; 
        }

        const validA = battleState.teamA.filter(c => c.mercenaryId);
        const validB = battleState.teamB.filter(c => c.mercenaryId);
        if (validA.length === 0 || validB.length === 0) return;

        setSingleMatchReport(null); 
        setBulkReport(null);
        setCombatLog([]); 
        matchStatsRef.current = { A: createInitialStats(), B: createInitialStats(), ticks: 0 };
        setLiveStats({ A: createInitialStats(), B: createInitialStats() });

        setBattleState(prev => {
            const resetTeam = (team: CombatantInstance[]) => team.map(c => {
                if (!c.mercenaryId) return c;
                const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
                return { ...c, currentHp: derived ? derived.maxHp : 0, gauge: 0, lastAttacker: false, lastDamaged: false, kills: 0, damageDealt: 0, damageTaken: 0 };
            });
            return { teamA: resetTeam(prev.teamA), teamB: resetTeam(prev.teamB) };
        });

        setIsBattleRunning(true);

        battleInterval.current = setInterval(() => {
            const speedMult = battleSpeedRef.current; 
            matchStatsRef.current.ticks++;

            setBattleState(prev => {
                const nextA = prev.teamA.map(c => {
                    return (c.mercenaryId && c.currentHp > 0) ? { ...c, gauge: c.gauge + (getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!.speed * 0.1 * speedMult) } : c;
                });
                const nextB = prev.teamB.map(c => {
                    return (c.mercenaryId && c.currentHp > 0) ? { ...c, gauge: c.gauge + (getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!.speed * 0.1 * speedMult) } : c;
                });

                const executeAttack = (att: CombatantInstance, side: 'A' | 'B') => {
                    const targets = (side === 'A' ? nextB : nextA).filter(c => c.mercenaryId && c.currentHp > 0);
                    if (targets.length === 0) return;
                    const target = targets[Math.floor(Math.random() * targets.length)];
                    const attD = getDerivedStats(att.mercenaryId, att.level, att.allocatedStats)!;
                    const defD = getDerivedStats(target.mercenaryId, target.level, target.allocatedStats)!;
                    const stats = side === 'A' ? matchStatsRef.current.A : matchStatsRef.current.B;
                    const enemyStats = side === 'A' ? matchStatsRef.current.B : matchStatsRef.current.A;

                    stats.attacks++;
                    att.gauge -= ACTION_THRESHOLD;
                    att.lastAttacker = true;

                    setTimeout(() => setBattleState(curr => ({ teamA: curr.teamA.map(c => c.instanceId === att.instanceId ? { ...c, lastAttacker: false } : c), teamB: curr.teamB.map(c => c.instanceId === att.instanceId ? { ...c, lastAttacker: false } : c) })), 120);

                    const res = calculateCombatResult(attD, defD, attD.magicalAttack > attD.physicalAttack ? 'MAGICAL' : 'PHYSICAL');
                    if (res.isHit) {
                        if (res.isCrit) stats.crits++;
                        stats.totalDmg += res.damage;
                        if (res.damage > stats.maxDmg) stats.maxDmg = res.damage;
                        if (stats.minDmg === 0 || res.damage < stats.minDmg) stats.minDmg = res.damage;

                        // Performance Stats
                        att.damageDealt += res.damage;
                        target.damageTaken += res.damage;
                        target.currentHp = Math.max(0, target.currentHp - res.damage);

                        // Kill Logic
                        if (target.currentHp <= 0) {
                            att.kills += 1;
                        }

                        // Trigger Damaged Animation
                        target.lastDamaged = true;
                        setTimeout(() => setBattleState(curr => ({ teamA: curr.teamA.map(c => c.instanceId === target.instanceId ? { ...c, lastDamaged: false } : c), teamB: curr.teamB.map(c => c.instanceId === target.instanceId ? { ...c, lastDamaged: false } : c) })), 200);

                        addLog(`${state.knownMercenaries.find(m=>m.id===att.mercenaryId)!.name} hits for ${res.damage}${res.isCrit ? "!" : ""}`, side, res.isCrit);
                    } else {
                        stats.misses++; enemyStats.evasions++;
                        addLog(`${state.knownMercenaries.find(m=>m.id===att.mercenaryId)!.name} missed!`, side, false, true);
                    }
                };

                nextA.filter(c => c.gauge >= ACTION_THRESHOLD && c.currentHp > 0).forEach(c => executeAttack(c, 'A'));
                nextB.filter(c => c.gauge >= ACTION_THRESHOLD && c.currentHp > 0).forEach(c => executeAttack(c, 'B'));

                const curA = nextA.filter(c => c.mercenaryId && c.currentHp > 0).length;
                const curB = nextB.filter(c => c.mercenaryId && c.currentHp > 0).length;

                setLiveStats({ A: { ...matchStatsRef.current.A }, B: { ...matchStatsRef.current.B } });

                if (curA === 0 || curB === 0) {
                    setIsBattleRunning(false); 
                    if (battleInterval.current) clearInterval(battleInterval.current);
                    setSingleMatchReport({ 
                        winner: curA > 0 ? 'A' : 'B', 
                        durationTicks: matchStatsRef.current.ticks, 
                        statsA: { ...matchStatsRef.current.A }, 
                        statsB: { ...matchStatsRef.current.B }, 
                        analysis: ["Battle Concluded."] 
                    });
                }
                return { teamA: nextA, teamB: nextB };
            });
        }, 40);
    };

    return {
        teamA: battleState.teamA, teamB: battleState.teamB, addSlot, removeSlot, updateSlot,
        combatLog, clearLogs, isBattleRunning, battleSpeed, setBattleSpeed,
        singleMatchReport, liveStats, bulkReport, isSearching,
        handleReset, runBulkSimulation, runAttackCycle, getDerivedStats
    };
};

import { PrimaryStats } from './Stats';

export enum JobClass {
  NOVICE = 'Novice',
  FIGHTER = 'Fighter',
  MAGE = 'Mage',
  ROGUE = 'Rogue',
  CLERIC = 'Cleric'
}

export const JOB_STAT_WEIGHTS: Record<JobClass, PrimaryStats> = {
  [JobClass.NOVICE]: { str: 1, vit: 1, dex: 1, int: 1, luk: 1 },
  [JobClass.FIGHTER]: { str: 3, vit: 3, dex: 1, int: 0, luk: 0 },
  [JobClass.MAGE]: { str: 0, vit: 1, dex: 1, int: 4, luk: 1 },
  [JobClass.ROGUE]: { str: 1, vit: 1, dex: 3, int: 1, luk: 2 },
  [JobClass.CLERIC]: { str: 1, vit: 2, dex: 0, int: 3, luk: 1 },
};

/**
 * JOB_EFFICIENCY
 * Defines the base attack efficiency for each job.
 * Actual efficiency is calculated as a random value between this base and 100%.
 */
export const JOB_EFFICIENCY: Record<JobClass, { physical: number; magical: number }> = {
  [JobClass.NOVICE]: { physical: 80, magical: 60 },
  [JobClass.FIGHTER]: { physical: 90, magical: 70 },
  [JobClass.MAGE]: { physical: 70, magical: 95 },
  [JobClass.ROGUE]: { physical: 85, magical: 75 },
  [JobClass.CLERIC]: { physical: 85, magical: 85 },
};

import { DerivedStats } from '../models/Stats';
import { DERIVED_CONFIG } from '../config/derived-stats-config';
import { JobClass, JOB_EFFICIENCY } from '../models/JobClass';

export interface CombatResult {
  isHit: boolean;
  isCrit: boolean;
  damage: number;
  hitChance: number;
  efficiency: number;
}

// Standard target for DPS measurement (Average mid-game enemy)
const STANDARD_DEFENSE = 150;
const STANDARD_EVASION = 50;

/**
 * Optimized combat result calculation.
 */
export const calculateCombatResult = (
  attacker: DerivedStats,
  defender: DerivedStats,
  attackerJob: JobClass,
  type: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'
): CombatResult => {
  const acc = attacker.accuracy;
  const eva = defender.evasion;

  // Step 0: Hit Probability Check
  // Clamped to 90-100% range as per previous high-efficiency standard
  const rawHitChance = (acc / (acc + eva * 0.7)) * 100;
  const hitChance = rawHitChance > 100 ? 100 : (rawHitChance < 90 ? 90 : rawHitChance);

  if (Math.random() * 100 > hitChance) {
    return { isHit: false, isCrit: false, damage: 0, hitChance, efficiency: 0 };
  }

  // Step 1: Attacker Efficiency Transformation
  const baseEff = type === 'PHYSICAL' ? JOB_EFFICIENCY[attackerJob].physical : JOB_EFFICIENCY[attackerJob].magical;
  // Efficiency is a random value between [baseEff, 100]
  const transformedEfficiency = (Math.random() * (100 - baseEff) + baseEff) / 100;

  // Step 2: Multiply attack by efficiency
  const rawBaseAtk = type === 'PHYSICAL' ? attacker.physicalAttack : attacker.magicalAttack;
  const effectiveAtk = rawBaseAtk * transformedEfficiency;

  // Step 3: Defense reduction and Critical Hit
  const reduction = type === 'PHYSICAL' ? defender.physicalReduction : defender.magicalReduction;
  const baseDamageAfterDef = effectiveAtk * (1 - reduction);

  const isCrit = Math.random() * 100 <= attacker.critChance;
  const critMult = isCrit ? attacker.critDamage * 0.01 : 1.0;

  const damage = Math.max(1, Math.round(baseDamageAfterDef * critMult));

  return { isHit: true, isCrit, damage, hitChance, efficiency: transformedEfficiency * 100 };
};

/**
 * High-performance lightweight combat calculation for bulk simulations.
 */
export const calculateFastDmg = (
  atkValue: number,
  reduction: number,
  critChance: number,
  critDamage: number,
  hitChance: number,
  baseEfficiency: number
): number => {
  // Step 0: Hit Check
  if (Math.random() * 100 > hitChance) return 0;

  // Step 1 & 2: Efficiency and Transformed Atk
  const eff = (Math.random() * (100 - baseEfficiency) + baseEfficiency) / 100;
  const effectiveAtk = atkValue * eff;

  // Step 3: Def and Crit
  const isCrit = Math.random() * 100 <= critChance;
  const dmg = effectiveAtk * (1 - reduction) * (isCrit ? critDamage * 0.01 : 1.0);

  return dmg < 1 ? 1 : dmg;
};

/**
 * Calculates theoretical Expected Damage Per Second (DPS) against a standard target.
 */
export const calculateExpectedDPS = (stats: DerivedStats, job: JobClass, attackType: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'): number => {
    const critBonusMult = (stats.critChance * 0.01) * ((stats.critDamage * 0.01) - 1);
    const avgCritMult = 1 + critBonusMult;

    const baseEff = attackType === 'PHYSICAL' ? JOB_EFFICIENCY[job].physical : JOB_EFFICIENCY[job].magical;
    const avgEfficiency = (baseEff + 100) / 200; // Mean of random(base, 100) / 100

    const reduction = STANDARD_DEFENSE / (STANDARD_DEFENSE + 150);
    const rawAtk = attackType === 'PHYSICAL' ? stats.physicalAttack : stats.magicalAttack;

    // Base damage incorporating avg efficiency and avg crit
    const expectedDmgPerHit = (rawAtk * avgEfficiency) * (1 - reduction) * avgCritMult;

    const rawHitChance = (stats.accuracy / (stats.accuracy + STANDARD_EVASION * 0.7)) * 100;
    const hitChance = (rawHitChance > 100 ? 100 : (rawHitChance < 90 ? 90 : rawHitChance)) * 0.01;

    const actionsPerSecond = (stats.speed * 0.001) * 25;

    return Math.round(expectedDmgPerHit * hitChance * actionsPerSecond);
};

/**
 * Calculates overall Combat Power (CP).
 */
export const calculateCombatPower = (stats: DerivedStats, job: JobClass, attackType: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'): number => {
    const dps = calculateExpectedDPS(stats, job, attackType);
    const offensiveScore = dps * 12;

    const avgReduction = (stats.physicalReduction + stats.magicalReduction) * 0.5;
    const effectiveHp = stats.maxHp / Math.max(0.1, (1 - avgReduction));

    const evasionBonus = 1 + (stats.evasion * 0.005);
    const defensiveScore = (effectiveHp * evasionBonus) * 0.25;

    return Math.round((offensiveScore + defensiveScore) * 0.1);
};

import { Mercenary } from '../models/Mercenary';
import { mergePrimaryStats, calculateDerivedStats, applyEquipmentBonuses } from '../models/Stats';
import { calculateCombatPower } from './combatLogic';

export const calculateMercenaryPower = (merc: Mercenary): number => {
    // 1. Merge stats
    const primary = mergePrimaryStats(merc.stats, merc.allocatedStats);

    // 2. Base Derived
    const base = calculateDerivedStats(primary, merc.level);

    // 3. Apply Equipment
    const eqStatsList = Object.values(merc.equipment).map(e => e?.stats).filter(Boolean);
    const finalDerived = applyEquipmentBonuses(base, eqStatsList as any);

    // 4. Determine attack type based on highest stat
    const attackType = primary.int > primary.str ? 'MAGICAL' : 'PHYSICAL';

    // Pass merc.job to incorporate efficiency weights
    return calculateCombatPower(finalDerived, merc.job, attackType);
};

export const calculatePartyPower = (mercs: Mercenary[]): number => {
    return mercs.reduce((sum, m) => sum + calculateMercenaryPower(m), 0);
};

export const formatDuration = (ms: number): string => {
    if (ms <= 0) return '00:00';
    const totalSeconds = Math.floor(ms / 1000);
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
};

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { useGame } from '../context/GameContext';
import { Mercenary } from '../models/Mercenary';
import { calculateDerivedStats, applyEquipmentBonuses, DerivedStats, mergePrimaryStats, PrimaryStats } from '../models/Stats';
import { Equipment } from '../models/Equipment';
import { calculateCombatResult, calculateExpectedDPS, calculateFastDmg } from '../utils/combatLogic';
import { JobClass, JOB_EFFICIENCY } from '../models/JobClass';

const ACTION_THRESHOLD = 1000;
const MAX_SQUAD_SIZE = 4;

export interface CombatantInstance {
    instanceId: string;
    mercenaryId: string | null;
    level: number;
    allocatedStats: PrimaryStats;
    currentHp: number;
    gauge: number;
    dps: number;
    lastAttacker?: boolean;
    lastDamaged?: boolean;
    // Stats for MVP and performance tracking
    kills: number;
    damageDealt: number;
    damageTaken: number;
}

export interface MatchStats {
    totalDmg: number;
    crits: number;
    misses: number;
    attacks: number;
    evasions: number;
    maxDmg: number;
    minDmg: number;
}

export interface CombatLogEntry {
    msg: string;
    team: 'A' | 'B' | 'SYSTEM';
    isCrit?: boolean;
    isMiss?: boolean;
}

export interface SingleMatchReport {
    winner: 'A' | 'B' | null;
    durationTicks: number;
    statsA: MatchStats;
    statsB: MatchStats;
    analysis: string[];
}

export interface BulkReport {
    rounds: number;
    winA: number;
    winB: number;
    avgAtksA: number;
    avgAtksB: number;
    avgCritsA: number;
    avgCritsB: number;
    avgEvasionsA: number;
    avgEvasionsB: number;
}

export interface SimulationHook {
    teamA: CombatantInstance[];
    teamB: CombatantInstance[];
    addSlot: (side: 'A' | 'B') => void;
    removeSlot: (side: 'A' | 'B', instanceId: string) => void;
    updateSlot: (side: 'A' | 'B', instanceId: string, data: Partial<CombatantInstance>) => void;
    combatLog: CombatLogEntry[];
    clearLogs: () => void;
    isBattleRunning: boolean;
    battleSpeed: 1 | 2 | 5 | 10;
    setBattleSpeed: (speed: 1 | 2 | 5 | 10) => void;
    singleMatchReport: SingleMatchReport | null;
    liveStats: { A: MatchStats, B: MatchStats } | null;
    bulkReport: BulkReport | null;
    isSearching: boolean;
    handleReset: () => void;
    runBulkSimulation: () => void;
    runAttackCycle: () => void;
    getDerivedStats: (mercId: string | null, level: number, alloc: PrimaryStats) => DerivedStats | null;
}

const createEmptyCombatant = (): CombatantInstance => ({
    instanceId: `inst_${Math.random().toString(36).substr(2, 9)}`,
    mercenaryId: null,
    level: 1,
    allocatedStats: { str: 0, vit: 0, dex: 0, int: 0, luk: 0 },
    currentHp: 0,
    gauge: 0,
    dps: 0,
    kills: 0,
    damageDealt: 0,
    damageTaken: 0
});

const createInitialStats = (): MatchStats => ({
    totalDmg: 0, crits: 0, misses: 0, attacks: 0, evasions: 0, maxDmg: 0, minDmg: 0
});

export const useSimulation = (): SimulationHook => {
    const { state } = useGame();

    const [battleState, setBattleState] = useState<{
        teamA: CombatantInstance[],
        teamB: CombatantInstance[]
    }>({
        teamA: [createEmptyCombatant()],
        teamB: [createEmptyCombatant()]
    });

    const [combatLog, setCombatLog] = useState<CombatLogEntry[]>([]);
    const [isBattleRunning, setIsBattleRunning] = useState(false);
    const [battleSpeed, setBattleSpeed] = useState<1 | 2 | 5 | 10>(1);
    const [singleMatchReport, setSingleMatchReport] = useState<SingleMatchReport | null>(null);
    const [liveStats, setLiveStats] = useState<{ A: MatchStats, B: MatchStats } | null>(null);
    const [bulkReport, setBulkReport] = useState<BulkReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);
    const battleSpeedRef = useRef<number>(1);
    const stopSearchRef = useRef(false);

    const matchStatsRef = useRef<{A: MatchStats, B: MatchStats, ticks: number}>({
        A: createInitialStats(),
        B: createInitialStats(),
        ticks: 0
    });

    const statsCache = useRef<Map<string, { key: string, stats: DerivedStats }>>(new Map());

    useEffect(() => { battleSpeedRef.current = battleSpeed; }, [battleSpeed]);

    const getDerivedStats = useCallback((mercId: string | null, level: number, alloc: PrimaryStats) => {
        if (!mercId) return null;

        const merc = state.knownMercenaries.find(m => m.id === mercId);
        if (!merc) return null;

        const cacheKey = `${mercId}_${level}_${alloc.str}_${alloc.vit}_${alloc.dex}_${alloc.int}_${alloc.luk}`;
        const cached = statsCache.current.get(mercId);
        if (cached && cached.key === cacheKey) return cached.stats;

        const primary = mergePrimaryStats(merc.stats, alloc);
        const base = calculateDerivedStats(primary, level);
        const eqStats = (Object.values(merc.equipment) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean);
        const stats = applyEquipmentBonuses(base, eqStats as any);

        statsCache.current.set(mercId, { key: cacheKey, stats });
        return stats;
    }, [state.knownMercenaries]);

    useEffect(() => {
        if (isBattleRunning) return;
        const refreshTeam = (team: CombatantInstance[]) => team.map(c => {
            if (!c.mercenaryId) return c;
            const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
            const merc = state.knownMercenaries.find(m => m.id === c.mercenaryId);
            if (!derived || !merc) return c;
            const isMage = derived.magicalAttack > derived.physicalAttack;
            return { ...c, dps: calculateExpectedDPS(derived, merc.job, isMage ? 'MAGICAL' : 'PHYSICAL') };
        });

        setBattleState(prev => ({
            teamA: refreshTeam(prev.teamA),
            teamB: refreshTeam(prev.teamB)
        }));
    }, [state.knownMercenaries, getDerivedStats, isBattleRunning]);

    const addSlot = (side: 'A' | 'B') => {
        setBattleState(prev => {
            const teamKey = side === 'A' ? 'teamA' : 'teamB';
            if (prev[teamKey].length >= MAX_SQUAD_SIZE) return prev;
            return { ...prev, [teamKey]: [...prev[teamKey], createEmptyCombatant()] };
        });
    };

    const removeSlot = (side: 'A' | 'B', instanceId: string) => {
        setBattleState(prev => {
            const teamKey = side === 'A' ? 'teamA' : 'teamB';
            return { ...prev, [teamKey]: prev[teamKey].filter(i => i.instanceId !== instanceId) };
        });
    };

    const updateSlot = (side: 'A' | 'B', instanceId: string, data: Partial<CombatantInstance>) => {
        setBattleState(prev => {
            const teamKey = side === 'A' ? 'teamA' : 'teamB';
            const newTeam = prev[teamKey].map(item => {
                if (item.instanceId !== instanceId) return item;
                let updated = { ...item, ...data };

                if (data.mercenaryId !== undefined && data.mercenaryId !== null) {
                    const merc = state.knownMercenaries.find(m => m.id === data.mercenaryId);
                    if (merc) {
                        updated.level = merc.level;
                        updated.allocatedStats = { ...merc.allocatedStats };
                    }
                }

                if (data.mercenaryId !== undefined || data.level !== undefined || data.allocatedStats !== undefined) {
                    const derived = getDerivedStats(updated.mercenaryId, updated.level, updated.allocatedStats);
                    const merc = state.knownMercenaries.find(m => m.id === updated.mercenaryId);
                    if (derived && merc) {
                        updated.currentHp = derived.maxHp;
                        const isMage = derived.magicalAttack > derived.physicalAttack;
                        updated.dps = calculateExpectedDPS(derived, merc.job, isMage ? 'MAGICAL' : 'PHYSICAL');
                    }
                }
                return updated;
            });
            return { ...prev, [teamKey]: newTeam };
        });
    };

    const addLog = (msg: string, team: 'A' | 'B' | 'SYSTEM' = 'SYSTEM', isCrit = false, isMiss = false) => {
        setCombatLog(prev => [...prev, { msg, team, isCrit, isMiss }].slice(-100));
    };

    const clearLogs = useCallback(() => {
        setCombatLog([]);
    }, []);

    const handleReset = useCallback(() => {
        setIsBattleRunning(false); setIsSearching(false); stopSearchRef.current = true;
        if (battleInterval.current) clearInterval(battleInterval.current);

        const resetTeam = (team: CombatantInstance[]) => team.map(c => {
            if (!c.mercenaryId) return c;
            const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
            return { ...c, currentHp: derived ? derived.maxHp : 0, gauge: 0, lastAttacker: false, lastDamaged: false, kills: 0, damageDealt: 0, damageTaken: 0 };
        });

        setBattleState(prev => ({ teamA: resetTeam(prev.teamA), teamB: resetTeam(prev.teamB) }));
        setCombatLog([]);
        setSingleMatchReport(null); setBulkReport(null); setLiveStats(null);
        matchStatsRef.current = { A: createInitialStats(), B: createInitialStats(), ticks: 0 };
    }, [getDerivedStats]);

    const runBulkSimulation = () => {
        if (isSearching) return;
        setBulkReport(null);
        const rounds = 10000;
        let winA = 0;
        let totalAtksA = 0, totalAtksB = 0;
        let totalCritsA = 0, totalCritsB = 0;
        let totalEvasionsA = 0, totalEvasionsB = 0;

        const teamAData = battleState.teamA.filter(c => c.mercenaryId).map(c => {
            const d = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!;
            const merc = state.knownMercenaries.find(m => m.id === c.mercenaryId)!;
            const isMage = d.magicalAttack > d.physicalAttack;
            const baseEff = isMage ? JOB_EFFICIENCY[merc.job].magical : JOB_EFFICIENCY[merc.job].physical;
            return { hp: d.maxHp, spd: d.speed, atk: isMage ? d.magicalAttack : d.physicalAttack, red: isMage ? d.magicalReduction : d.physicalReduction, crt: d.critChance, cdmg: d.critDamage, baseEff };
        });
        const teamBData = battleState.teamB.filter(c => c.mercenaryId).map(c => {
            const d = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!;
            const merc = state.knownMercenaries.find(m => m.id === c.mercenaryId)!;
            const isMage = d.magicalAttack > d.physicalAttack;
            const baseEff = isMage ? JOB_EFFICIENCY[merc.job].magical : JOB_EFFICIENCY[merc.job].physical;
            return { hp: d.maxHp, spd: d.speed, atk: isMage ? d.magicalAttack : d.physicalAttack, red: isMage ? d.magicalReduction : d.physicalReduction, crt: d.critChance, cdmg: d.critDamage, baseEff };
        });

        if (teamAData.length === 0 || teamBData.length === 0) return;

        for (let i = 0; i < rounds; i++) {
            const hpsA = new Float32Array(teamAData.map(d => d.hp));
            const hpsB = new Float32Array(teamBData.map(d => d.hp));
            const gaugesA = new Float32Array(teamAData.length);
            const gaugesB = new Float32Array(teamBData.length);
            let aliveA = teamAData.length;
            let aliveB = teamBData.length;

            while (aliveA > 0 && aliveB > 0) {
                for (let j = 0; j < teamAData.length; j++) if (hpsA[j] > 0) gaugesA[j] += teamAData[j].spd;
                for (let j = 0; j < teamBData.length; j++) if (hpsB[j] > 0) gaugesB[j] += teamBData[j].spd;

                for (let j = 0; j < teamAData.length; j++) {
                    if (gaugesA[j] >= ACTION_THRESHOLD && hpsA[j] > 0) {
                        gaugesA[j] -= ACTION_THRESHOLD;
                        const targets = [];
                        for(let k=0; k<hpsB.length; k++) if(hpsB[k]>0) targets.push(k);
                        if(targets.length === 0) break;
                        const tIdx = targets[Math.floor(Math.random()*targets.length)];
                        totalAtksA++;
                        const dmg = calculateFastDmg(teamAData[j].atk, teamBData[tIdx].red, teamAData[j].crt, teamAData[j].cdmg, 95, teamAData[j].baseEff); 
                        if(dmg > 0) { hpsB[tIdx] -= dmg; if(hpsB[tIdx] <= 0) aliveB--; } else { totalEvasionsB++; }
                    }
                }
                if (aliveB <= 0) break;
                for (let j = 0; j < teamBData.length; j++) {
                    if (gaugesB[j] >= ACTION_THRESHOLD && hpsB[j] > 0) {
                        gaugesB[j] -= ACTION_THRESHOLD;
                        const targets = [];
                        for(let k=0; k<hpsA.length; k++) if(hpsA[k]>0) targets.push(k);
                        if(targets.length === 0) break;
                        const tIdx = targets[Math.floor(Math.random()*targets.length)];
                        totalAtksB++;
                        const dmg = calculateFastDmg(teamBData[j].atk, teamAData[tIdx].red, teamBData[j].crt, teamBData[j].cdmg, 95, teamBData[j].baseEff);
                        if(dmg > 0) { hpsA[tIdx] -= dmg; if(hpsA[tIdx] <= 0) aliveA--; } else { totalEvasionsA++; }
                    }
                }
            }
            if (aliveA > 0) winA++;
        }
        setBulkReport({ rounds, winA, winB: rounds - winA, avgAtksA: totalAtksA / rounds, avgAtksB: totalAtksB / rounds, avgCritsA: totalCritsA / rounds, avgCritsB: totalCritsB / rounds, avgEvasionsA: totalEvasionsA / rounds, avgEvasionsB: totalEvasionsB / rounds });
    };

    const runAttackCycle = () => {
        if (isBattleRunning) { 
            setIsBattleRunning(false); 
            if (battleInterval.current) clearInterval(battleInterval.current); 
            return; 
        }

        const validA = battleState.teamA.filter(c => c.mercenaryId);
        const validB = battleState.teamB.filter(c => c.mercenaryId);
        if (validA.length === 0 || validB.length === 0) return;

        setSingleMatchReport(null); 
        setBulkReport(null);
        setCombatLog([]); 
        matchStatsRef.current = { A: createInitialStats(), B: createInitialStats(), ticks: 0 };
        setLiveStats({ A: createInitialStats(), B: createInitialStats() });

        setBattleState(prev => {
            const resetTeam = (team: CombatantInstance[]) => team.map(c => {
                if (!c.mercenaryId) return c;
                const derived = getDerivedStats(c.mercenaryId, c.level, c.allocatedStats);
                return { ...c, currentHp: derived ? derived.maxHp : 0, gauge: 0, lastAttacker: false, lastDamaged: false, kills: 0, damageDealt: 0, damageTaken: 0 };
            });
            return { teamA: resetTeam(prev.teamA), teamB: resetTeam(prev.teamB) };
        });

        setIsBattleRunning(true);

        battleInterval.current = setInterval(() => {
            const speedMult = battleSpeedRef.current; 
            matchStatsRef.current.ticks++;

            setBattleState(prev => {
                const nextA = prev.teamA.map(c => {
                    return (c.mercenaryId && c.currentHp > 0) ? { ...c, gauge: c.gauge + (getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!.speed * 0.1 * speedMult) } : c;
                });
                const nextB = prev.teamB.map(c => {
                    return (c.mercenaryId && c.currentHp > 0) ? { ...c, gauge: c.gauge + (getDerivedStats(c.mercenaryId, c.level, c.allocatedStats)!.speed * 0.1 * speedMult) } : c;
                });

                const executeAttack = (att: CombatantInstance, side: 'A' | 'B') => {
                    const targets = (side === 'A' ? nextB : nextA).filter(c => c.mercenaryId && c.currentHp > 0);
                    if (targets.length === 0) return;
                    const target = targets[Math.floor(Math.random() * targets.length)];
                    const attD = getDerivedStats(att.mercenaryId, att.level, att.allocatedStats)!;
                    const defD = getDerivedStats(target.mercenaryId, target.level, target.allocatedStats)!;
                    const attMerc = state.knownMercenaries.find(m => m.id === att.mercenaryId)!;
                    const stats = side === 'A' ? matchStatsRef.current.A : matchStatsRef.current.B;
                    const enemyStats = side === 'A' ? matchStatsRef.current.B : matchStatsRef.current.A;

                    stats.attacks++;
                    att.gauge -= ACTION_THRESHOLD;
                    att.lastAttacker = true;

                    setTimeout(() => setBattleState(curr => ({ teamA: curr.teamA.map(c => c.instanceId === att.instanceId ? { ...c, lastAttacker: false } : c), teamB: curr.teamB.map(c => c.instanceId === att.instanceId ? { ...c, lastAttacker: false } : c) })), 120);

                    const res = calculateCombatResult(attD, defD, attMerc.job, attD.magicalAttack > attD.physicalAttack ? 'MAGICAL' : 'PHYSICAL');
                    if (res.isHit) {
                        if (res.isCrit) stats.crits++;
                        stats.totalDmg += res.damage;
                        if (res.damage > stats.maxDmg) stats.maxDmg = res.damage;
                        if (stats.minDmg === 0 || res.damage < stats.minDmg) stats.minDmg = res.damage;

                        // Performance Stats
                        att.damageDealt += res.damage;
                        target.damageTaken += res.damage;
                        target.currentHp = Math.max(0, target.currentHp - res.damage);

                        // Kill Logic
                        if (target.currentHp <= 0) {
                            att.kills += 1;
                        }

                        // Trigger Damaged Animation
                        target.lastDamaged = true;
                        setTimeout(() => setBattleState(curr => ({ teamA: curr.teamA.map(c => c.instanceId === target.instanceId ? { ...c, lastDamaged: false } : c), teamB: curr.teamB.map(c => c.instanceId === target.instanceId ? { ...c, lastDamaged: false } : c) })), 200);

                        addLog(`${state.knownMercenaries.find(m=>m.id===att.mercenaryId)!.name} hits for ${res.damage}${res.isCrit ? "!" : ""}`, side, res.isCrit);
                    } else {
                        stats.misses++; enemyStats.evasions++;
                        addLog(`${state.knownMercenaries.find(m=>m.id===att.mercenaryId)!.name} missed!`, side, false, true);
                    }
                };

                nextA.filter(c => c.gauge >= ACTION_THRESHOLD && c.currentHp > 0).forEach(c => executeAttack(c, 'A'));
                nextB.filter(c => c.gauge >= ACTION_THRESHOLD && c.currentHp > 0).forEach(c => executeAttack(c, 'B'));

                const curA = nextA.filter(c => c.mercenaryId && c.currentHp > 0).length;
                const curB = nextB.filter(c => c.mercenaryId && c.currentHp > 0).length;

                setLiveStats({ A: { ...matchStatsRef.current.A }, B: { ...matchStatsRef.current.B } });

                if (curA === 0 || curB === 0) {
                    setIsBattleRunning(false); 
                    if (battleInterval.current) clearInterval(battleInterval.current);
                    setSingleMatchReport({ 
                        winner: curA > 0 ? 'A' : 'B', 
                        durationTicks: matchStatsRef.current.ticks, 
                        statsA: { ...matchStatsRef.current.A }, 
                        statsB: { ...matchStatsRef.current.B }, 
                        analysis: ["Battle Concluded."] 
                    });
                }
                return { teamA: nextA, teamB: nextB };
            });
        }, 40);
    };

    return {
        teamA: battleState.teamA, teamB: battleState.teamB, addSlot, removeSlot, updateSlot,
        combatLog, clearLogs, isBattleRunning, battleSpeed, setBattleSpeed,
        singleMatchReport, liveStats, bulkReport, isSearching,
        handleReset, runBulkSimulation, runAttackCycle, getDerivedStats
    };
};

import React, { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../context/GameContext';
import { Mercenary } from '../../models/Mercenary';
import { EquipmentSlotType } from '../../types/inventory';
import { X, Sword, Shield, Shirt, Hand, Footprints, Crown, Sparkles, Heart, Activity, Star, Box, Zap, Brain, Target, User, Plus, Wind, FastForward, Crosshair, Minus, Check, RefreshCw, AlertCircle, ShieldAlert, ArrowUp, ArrowDown } from 'lucide-react';
import { getAssetUrl } from '../../utils';
import { calculateDerivedStats, applyEquipmentBonuses, DerivedStats, PrimaryStats, mergePrimaryStats } from '../../models/Stats';
import { calculateCombatPower } from '../../utils/combatLogic';
