import { DerivedStats, mergePrimaryStats, calculateDerivedStats, applyEquipmentBonuses } from '../models/Stats';
import { DERIVED_CONFIG } from '../config/derived-stats-config';
import { JobClass, JOB_EFFICIENCY } from '../models/JobClass';
import { Mercenary } from '../models/Mercenary';

export interface CombatResult {
  isHit: boolean;
  isCrit: boolean;
  damage: number;
  hitChance: number;
  efficiency: number;
}

// Standard target for DPS measurement (Average mid-game enemy)
const STANDARD_DEFENSE = 150;
const STANDARD_EVASION = 50;

/**
 * Optimized combat result calculation.
 */
export const calculateCombatResult = (
  attacker: DerivedStats,
  defender: DerivedStats,
  attackerJob: JobClass,
  type: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'
): CombatResult => {
  const acc = attacker.accuracy;
  const eva = defender.evasion;

  // Step 0: Hit Probability Check
  // Clamped to 90-100% range as per previous high-efficiency standard
  const rawHitChance = (acc / (acc + eva * 0.7)) * 100;
  const hitChance = rawHitChance > 100 ? 100 : (rawHitChance < 90 ? 90 : rawHitChance);

  if (Math.random() * 100 > hitChance) {
    return { isHit: false, isCrit: false, damage: 0, hitChance, efficiency: 0 };
  }

  // Step 1: Attacker Efficiency Transformation
  const baseEff = type === 'PHYSICAL' ? JOB_EFFICIENCY[attackerJob].physical : JOB_EFFICIENCY[attackerJob].magical;
  // Efficiency is a random value between [baseEff, 100]
  const transformedEfficiency = (Math.random() * (100 - baseEff) + baseEff) / 100;

  // Step 2: Multiply attack by efficiency
  const rawBaseAtk = type === 'PHYSICAL' ? attacker.physicalAttack : attacker.magicalAttack;
  const effectiveAtk = rawBaseAtk * transformedEfficiency;

  // Step 3: Defense reduction and Critical Hit
  const reduction = type === 'PHYSICAL' ? defender.physicalReduction : defender.magicalReduction;
  const baseDamageAfterDef = effectiveAtk * (1 - reduction);

  const isCrit = Math.random() * 100 <= attacker.critChance;
  const critMult = isCrit ? attacker.critDamage * 0.01 : 1.0;

  const damage = Math.max(1, Math.round(baseDamageAfterDef * critMult));

  return { isHit: true, isCrit, damage, hitChance, efficiency: transformedEfficiency * 100 };
};

/**
 * High-performance lightweight combat calculation for bulk simulations.
 */
export const calculateFastDmg = (
  atkValue: number,
  reduction: number,
  critChance: number,
  critDamage: number,
  hitChance: number,
  baseEfficiency: number
): number => {
  // Step 0: Hit Check
  if (Math.random() * 100 > hitChance) return 0;

  // Step 1 & 2: Efficiency and Transformed Atk
  const eff = (Math.random() * (100 - baseEfficiency) + baseEfficiency) / 100;
  const effectiveAtk = atkValue * eff;

  // Step 3: Def and Crit
  const isCrit = Math.random() * 100 <= critChance;
  const dmg = effectiveAtk * (1 - reduction) * (isCrit ? critDamage * 0.01 : 1.0);

  return dmg < 1 ? 1 : dmg;
};

/**
 * Calculates theoretical Expected Damage Per Second (DPS) against a standard target.
 */
export const calculateExpectedDPS = (stats: DerivedStats, job: JobClass, attackType: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'): number => {
    const critBonusMult = (stats.critChance * 0.01) * ((stats.critDamage * 0.01) - 1);
    const avgCritMult = 1 + critBonusMult;

    const baseEff = attackType === 'PHYSICAL' ? JOB_EFFICIENCY[job].physical : JOB_EFFICIENCY[job].magical;
    const avgEfficiency = (baseEff + 100) / 200; // Mean of random(base, 100) / 100

    const reduction = STANDARD_DEFENSE / (STANDARD_DEFENSE + 150);
    const rawAtk = attackType === 'PHYSICAL' ? stats.physicalAttack : stats.magicalAttack;

    // Base damage incorporating avg efficiency and avg crit
    const expectedDmgPerHit = (rawAtk * avgEfficiency) * (1 - reduction) * avgCritMult;

    const rawHitChance = (stats.accuracy / (stats.accuracy + STANDARD_EVASION * 0.7)) * 100;
    const hitChance = (rawHitChance > 100 ? 100 : (rawHitChance < 90 ? 90 : rawHitChance)) * 0.01;

    const actionsPerSecond = (stats.speed * 0.001) * 25;

    return Math.round(expectedDmgPerHit * hitChance * actionsPerSecond);
};

/**
 * Calculates overall Combat Power (CP).
 */
export const calculateCombatPower = (stats: DerivedStats, job: JobClass, attackType: 'PHYSICAL' | 'MAGICAL' = 'PHYSICAL'): number => {
    const dps = calculateExpectedDPS(stats, job, attackType);
    const offensiveScore = dps * 12;

    const avgReduction = (stats.physicalReduction + stats.magicalReduction) * 0.5;
    const effectiveHp = stats.maxHp / Math.max(0.1, (1 - avgReduction));

    const evasionBonus = 1 + (stats.evasion * 0.005);
    const defensiveScore = (effectiveHp * evasionBonus) * 0.25;

    return Math.round((offensiveScore + defensiveScore) * 0.1);
};

/**
 * Calculates the individual Combat Power (CP) of a mercenary,
 * incorporating their base stats, allocated points, and equipped gear.
 */
export const calculateMercenaryPower = (merc: Mercenary): number => {
    // 1. Merge stats (Base + Level up points)
    const primary = mergePrimaryStats(merc.stats, merc.allocatedStats);

    // 2. Calculate Base Derived Stats (HP, MP, Attack etc.)
    const base = calculateDerivedStats(primary, merc.level);

    // 3. Apply Equipment Bonuses
    const eqStatsList = Object.values(merc.equipment).map(e => e?.stats).filter(Boolean);
    const finalDerived = applyEquipmentBonuses(base, eqStatsList as any);

    // 4. Determine attack type based on the dominant primary stat
    const attackType = primary.int > primary.str ? 'MAGICAL' : 'PHYSICAL';

    // 5. Calculate CP using the job-specific efficiency logic
    return calculateCombatPower(finalDerived, merc.job, attackType);
};

/**
 * Calculates the combined power of a full party.
 */
export const calculatePartyPower = (mercs: Mercenary[]): number => {
    return mercs.reduce((sum, m) => sum + calculateMercenaryPower(m), 0);
};

const SESSION_VERSION = Date.now();

export const getAssetUrl = (filename: string): string => {
  const baseUrl = 'https://raw.githubusercontent.com/cryingdev/lockharts-forge/sub/assets/';
  // Use the static session version to cache images for the duration of the session
  return `${baseUrl}${filename}?v=${SESSION_VERSION}`;
};

/**
 * Formats a duration in milliseconds to a MM:SS string.
 */
export const formatDuration = (ms: number): string => {
    if (ms <= 0) return '00:00';
    const totalSeconds = Math.floor(ms / 1000);
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
};

import React, { useState, useMemo, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import { MATERIALS } from '../../../data/materials';
import { EQUIPMENT_ITEMS } from '../../../data/equipment';
import { calculatePartyPower, calculateMercenaryPower } from '../../../utils/combatLogic';
import { Sword, Skull, Timer, Zap, Map as MapIcon, ChevronRight, ChevronLeft, Lock, CheckCircle, Trophy, User, XCircle, Triangle, Box, AlertCircle, Gamepad2, Navigation2, Play } from 'lucide-react';
import { getAssetUrl, formatDuration } from '../../../utils';
import AssaultNavigator from './AssaultNavigator';

const DungeonTab = () => {
    const { state, actions } = useGame();
    const { activeExpeditions, knownMercenaries, dungeonClearCounts, unlockedRecipes, inventory, activeManualDungeon, showManualDungeonOverlay } = state;

    // Index-based selection for paging
    const [selectedIndex, setSelectedIndex] = useState(0);
    const [party, setParty] = useState<string[]>([]);
    const [failedMercs, setFailedMercs] = useState<string[]>([]);
    const [failedPowerHighlight, setFailedPowerHighlight] = useState(false);

    const selectedDungeon = DUNGEONS[selectedIndex];

    // Check if this specific dungeon is the one being manually assaulted
    const isOngoingManual = activeManualDungeon && activeManualDungeon.dungeonId === selectedDungeon.id;

    const hiredMercs = useMemo(() => knownMercenaries.filter(m => m.status === 'HIRED'), [knownMercenaries]);
    const currentExpedition = activeExpeditions.find(e => e.dungeonId === selectedDungeon.id);

    const isMercBusy = (mercId: string) => {
        return activeExpeditions.some(e => e.partyIds.includes(mercId));
    };

    const handlePrev = () => {
        setSelectedIndex(prev => (prev > 0 ? prev - 1 : DUNGEONS.length - 1));
        setParty([]);
        setFailedMercs([]);
        setFailedPowerHighlight(false);
    };

    const handleNext = () => {
        setSelectedIndex(prev => (prev < DUNGEONS.length - 1 ? prev + 1 : 0));
        setParty([]);
        setFailedMercs([]);
        setFailedPowerHighlight(false);
    };

    const toggleMercenary = (mercId: string) => {
        if (party.includes(mercId)) {
            setParty(prev => prev.filter(id => id !== mercId));
        } else {
            if (party.length < 4) {
                setParty(prev => [...prev, mercId]);
            }
        }
        if (failedMercs.includes(mercId)) {
            setFailedMercs(prev => prev.filter(id => id !== mercId));
        }
    };

    const validateEntry = () => {
        if (party.length === 0 || !selectedDungeon) return false;

        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        const lowEnergyIds = selectedMercs
            .filter(m => (m.expeditionEnergy || 0) < selectedDungeon.energyCost)
            .map(m => m.id);

        if (lowEnergyIds.length > 0) {
            setFailedMercs(lowEnergyIds);
            setTimeout(() => setFailedMercs([]), 2000);
            actions.showToast("Some squad members are too exhausted.");
            return false;
        }

        if (currentPartyPower < selectedDungeon.requiredPower) {
            setFailedPowerHighlight(true);
            setTimeout(() => setFailedPowerHighlight(false), 2000);
            actions.showToast("Party power is insufficient for this area.");
            return false;
        }

        return true;
    };

    const handleStartAutoExpedition = () => {
        if (!validateEntry()) return;
        actions.startExpedition(selectedDungeon.id, party);
    };

    const handleStartManualAssault = () => {
        if (isOngoingManual) {
            actions.toggleManualDungeonOverlay(true);
            return;
        }
        if (!validateEntry()) return;
        actions.startManualAssault(selectedDungeon.id, party);
    };

    const handleClaim = (expId: string) => {
        actions.claimExpedition(expId);
    };

    const currentPartyPower = useMemo(() => {
        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        return calculatePartyPower(selectedMercs);
    }, [party, knownMercenaries]);

    const canStartStatus = useMemo(() => {
        if (!selectedDungeon) return false;
        if (party.length === 0) return false;
        if (currentPartyPower < selectedDungeon.requiredPower) return false;

        const selectedMercs = knownMercenaries.filter(m => party.includes(m.id));
        const hasEnergy = selectedMercs.every(m => (m.expeditionEnergy || 0) >= selectedDungeon.energyCost);

        return hasEnergy;
    }, [selectedDungeon, party, currentPartyPower, knownMercenaries]);

    const [timeLeft, setTimeLeft] = useState<string>('');
    const isComplete = currentExpedition?.status === 'COMPLETED';

    useEffect(() => {
        if (!currentExpedition) {
            setTimeLeft('');
            return;
        }
        if (currentExpedition.status === 'COMPLETED') {
            setTimeLeft('00:00');
            return;
        }

        const updateTimer = () => {
            const now = Date.now();
            const end = currentExpedition.endTime;
            const diff = end - now;
            if (diff <= 0) setTimeLeft('00:00');
            else setTimeLeft(formatDuration(diff));
        };

        updateTimer();
        const interval = setInterval(updateTimer, 1000);

        return () => clearInterval(interval);
    }, [currentExpedition]);

    const isUnlocked = selectedDungeon.tier <= state.stats.tierLevel + 1;
    const clears = dungeonClearCounts[selectedDungeon.id] || 0;
    const isBoss = !!selectedDungeon.bossVariantId;

    const displayRewards = useMemo(() => {
        const base = [...selectedDungeon.rewards];
        if (selectedDungeon.id === 'dungeon_t1_rats') {
            const targetId = 'sword_bronze_long_t1';
            const itemDef = EQUIPMENT_ITEMS.find(i => i.id === targetId);
            const isItemAlreadyUnlocked = itemDef?.unlockedByDefault !== false || unlockedRecipes.includes(targetId);
            const hasScroll = inventory.some(i => i.id === 'recipe_scroll_bronze_longsword');

            if (clears === 0 && !isItemAlreadyUnlocked && !hasScroll) {
                base.push({ itemId: 'recipe_scroll_bronze_longsword', minQuantity: 1, maxQuantity: 1, chance: 1.0 });
            }
        }
        return base;
    }, [selectedDungeon, clears, unlockedRecipes, inventory]);

    return (
        <div className="h-full w-full flex flex-col sm:flex-row bg-stone-950 text-stone-200 overflow-hidden font-sans relative">

            {(activeManualDungeon && showManualDungeonOverlay) && <AssaultNavigator />}

            {/* Left/Upper Panel: Dungeon Selection */}
            <div className="w-full sm:w-[40%] h-[42%] sm:h-full flex flex-col border-b sm:border-b-0 sm:border-r border-stone-800 bg-stone-900/50 relative overflow-hidden shrink-0 min-h-0">
                <div className="absolute inset-0 opacity-10 pointer-events-none">
                    <img src={getAssetUrl('dungeon_bg.png')} className="w-full h-full object-cover grayscale" />
                </div>

                <div key={selectedDungeon.id} className="flex-1 flex flex-col items-center z-10 min-h-0 transform-gpu backface-hidden">

                    <div className="relative flex flex-col items-center pt-3 sm:pt-10 z-10 shrink-0 w-full">
                        <div className="h-14 sm:h-24 flex flex-col items-center justify-center text-center px-10 mb-1 sm:mb-4">
                            <h1 className="text-base sm:text-2xl lg:text-3xl font-black text-white font-serif tracking-tighter uppercase leading-none animate-in fade-in duration-300">
                                {selectedDungeon.name}
                            </h1>
                            {!isUnlocked && (
                                <div className="flex items-center justify-center gap-1.5 text-red-500 font-bold text-[8px] sm:text-xs uppercase mt-1">
                                    <Lock className="w-2 sm:w-2.5 h-2 sm:h-2.5" /> Area Locked
                                </div>
                            )}
                        </div>

                        <div className="relative w-full flex items-center justify-center h-20 sm:h-40 mb-1 sm:mb-6">
                            <button 
                                onClick={handlePrev} 
                                className="absolute left-2 sm:left-4 z-30 p-2 sm:p-4 bg-stone-800/80 hover:bg-amber-600 rounded-full border border-stone-700 transition-all active:scale-90 group shadow-2xl backdrop-blur-md"
                            >
                                <ChevronLeft className="w-4 h-4 sm:w-8 sm:h-8 text-stone-400 group-hover:text-white" />
                            </button>

                            <div className="relative group animate-in fade-in zoom-in duration-300">
                                <div className={`absolute inset-0 blur-2xl rounded-full opacity-20 ${isBoss ? 'bg-red-500' : 'bg-amber-500'} group-hover:opacity-40 transition-opacity`}></div>

                                <div className={`w-16 h-16 sm:w-32 lg:w-40 sm:h-32 lg:h-40 bg-stone-900 rounded-[1.2rem] sm:rounded-[2rem] border-2 sm:border-4 border-stone-700 flex items-center justify-center relative shadow-2xl overflow-hidden ring-4 ring-white/5 ${!isUnlocked ? 'grayscale brightness-50' : ''}`}>
