export default TavernTab;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import Phaser from 'phaser';
import { X, Scissors } from 'lucide-react';
import { useGame } from '../../../context/GameContext';
import WorkbenchScene from '../../../game/WorkbenchScene';

interface WorkbenchMinigameProps {
  onComplete: (score: number, bonus?: number) => void;
  onClose: () => void;
  difficulty?: number;
}

function getViewport() {
  const vw = window.visualViewport?.width ?? window.innerWidth;
  const vh = window.visualViewport?.height ?? window.innerHeight;
  return { vw: Math.floor(vw), vh: Math.floor(vh) };
}

const WorkbenchMinigame: React.FC<WorkbenchMinigameProps> = ({ onComplete, onClose, difficulty = 1 }) => {
  const { state } = useGame();
  const gameRef = useRef<Phaser.Game | null>(null);

  const viewportRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isReady, setIsReady] = useState(false);

  const onCompleteRef = useRef(onComplete);
  useEffect(() => { onCompleteRef.current = onComplete; }, [onComplete]);

  // Determine current item type for path logic
  const itemType = state.isCrafting && state.lastCraftedItem === null ? 
    // This is a bit of a workaround to get the current recipe from the state
    // In a real scenario, we might want to store 'activeRecipe' in state
    null : null;

  useEffect(() => {
    const checkSize = () => {
      const el = containerRef.current;
      if (el && el.clientWidth > 0 && el.clientHeight > 0) setIsReady(true);
      else requestAnimationFrame(checkSize);
    };
    checkSize();
  }, []);

  useEffect(() => {
    if (!isReady) return;

    const viewportEl = viewportRef.current;
    const el = containerRef.current;
    if (!viewportEl || !el) return;

    const ensureWrapperSize = () => {
      const { vh } = getViewport();
      viewportEl.style.width = '100%';
      viewportEl.style.height = `${vh}px`;
      viewportEl.style.overflow = 'hidden';
      viewportEl.style.touchAction = 'none';

      el.style.width = '100%';
      el.style.height = '100%';
    };

    const resizePhaserToWrapper = () => {
      const game = gameRef.current;
      if (!game) return;
      const w = Math.floor(el.clientWidth);
      const h = Math.floor(el.clientHeight);
      if (w <= 0 || h <= 0) return;
      game.scale.resize(w, h);
      requestAnimationFrame(() => game.scale.refresh());
    };

    const sync = () => {
      ensureWrapperSize();
      resizePhaserToWrapper();
    };

    if (!gameRef.current) {
      ensureWrapperSize();

      const config: Phaser.Types.Core.GameConfig = {
        type: Phaser.AUTO,
        parent: el,
        width: Math.floor(el.clientWidth) || 1,
        height: Math.floor(el.clientHeight) || 1,
        backgroundColor: '#0c0a09',
        scene: [WorkbenchScene],
        scale: {
          mode: Phaser.Scale.RESIZE,
          autoCenter: Phaser.Scale.CENTER_BOTH,
        },
      };

      const game = new Phaser.Game(config);
      gameRef.current = game;

      // Extract current crafting item subCategoryId
      // We look for the most recently started crafting action
      // Since isCrafting is true, the item being crafted is implied
      // In this app, selectedItem in ForgeTab is what's being passed but we need it here.
      // For now, we will pass 'GLOVES' if it looks like we are making gloves.

      game.scene.start('WorkbenchScene', {
        onComplete: (score: number, bonus?: number) => onCompleteRef.current(score, bonus),
        difficulty,
        // Optional: Pass the specific item sub-category to determine shape
        // In this implementation, we rely on the component receiving this as a prop if needed
        // but for now we'll assume the scene can handle logic based on "itemType"
      });

      sync();
    } else {
      sync();
    }

    const vv = window.visualViewport;
    const onOrientationChange = () => {
      sync();
      setTimeout(sync, 100);
      setTimeout(sync, 300);
    };

    vv?.addEventListener('resize', sync);
    window.addEventListener('resize', sync);
    window.addEventListener('orientationchange', onOrientationChange);

    const ro = new ResizeObserver(() => requestAnimationFrame(sync));
    ro.observe(el);

    sync();
    setTimeout(sync, 80);

    return () => {
      ro.disconnect();
      vv?.removeEventListener('resize', sync);
      window.removeEventListener('resize', sync);
      window.removeEventListener('orientationchange', onOrientationChange);
    };
  }, [isReady, difficulty]);

  useEffect(() => {
    return () => {
      if (gameRef.current) {
        gameRef.current.destroy(true);
        gameRef.current = null;
      }
    };
  }, []);

  return (
    <div
      ref={viewportRef}
      className="fixed inset-0 z-[100] flex flex-col bg-stone-950 animate-in fade-in duration-300 overflow-hidden"
    >
      <div className="w-full h-12 md:h-16 shrink-0 bg-stone-900 border-b border-stone-800 flex items-center justify-between px-4 z-10 shadow-xl">
        <div className="flex items-center gap-3">
          <div className="p-1.5 bg-emerald-900/30 rounded-lg border border-emerald-800/50">
            <Scissors className="w-4 h-4 md:w-5 md:h-5 text-emerald-400" />
          </div>
          <span className="text-stone-200 font-bold text-xs md:text-base tracking-widest uppercase font-serif">Workbench</span>
        </div>
        <button
          onClick={onClose}
          className="flex items-center gap-2 px-4 py-1.5 bg-stone-800 hover:bg-red-900/40 text-stone-400 hover:text-red-300 rounded-lg border border-stone-700 transition-all text-[10px] md:text-xs font-black uppercase tracking-tighter"
        >
          <X className="w-3 h-3 md:w-4 md:h-4" /> Cancel
        </button>
      </div>

      <div className="flex-1 w-full relative flex items-center justify-center bg-[#1c1917] overflow-hidden">
        <div ref={containerRef} className="w-full h-full overflow-hidden" />
      </div>
    </div>
  );
};

export default WorkbenchMinigame;

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

type PathType = 'WAVE' | 'GLOVE';

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private targetNodes: Phaser.GameObjects.Arc[] = [];
  private cursor!: Phaser.GameObjects.Image; 
  private comboText!: Phaser.GameObjects.Text;

  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;

  private wavePathGraphics!: Phaser.GameObjects.Graphics;
  private bgImage!: Phaser.GameObjects.Image;

  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;

  private confirmedProgress = 0;
  private currentQuality = 100;
  private perfectStreak = 0;
  private combo = 0;
  private isFinished = false;

  private onComplete?: (score: number, bonus?: number) => void;

  private centerX = 0;
  private centerY = 0;
  private waveStartX = 0;
  private waveWidth = 0;
  private waveAmplitude = 0;
  private uiScale = 1;
  private isPortrait = false;

  private currentPathType: PathType = 'WAVE';

  // Normalized points for a "Glove" silhouette (X: 0 to 1, Y: -0.5 to 0.5)
  private readonly GLOVE_POINTS = [
    { x: 0.0, y: 0.4 },   // Wrist start
    { x: 0.05, y: 0.35 }, 
    { x: 0.1, y: 0.1 },   // Thumb tip
    { x: 0.18, y: 0.3 },  // Webbing 1
    { x: 0.25, y: -0.1 }, // Index tip
    { x: 0.32, y: 0.3 },  // Webbing 2
    { x: 0.42, y: -0.3 }, // Middle tip
    { x: 0.52, y: 0.3 },  // Webbing 3
    { x: 0.62, y: -0.1 }, // Ring tip
    { x: 0.7, y: 0.3 },   // Webbing 4
    { x: 0.8, y: 0.1 },   // Pinky tip
    { x: 0.9, y: 0.4 },   // Edge of hand
    { x: 1.0, y: 0.4 }    // Wrist end
  ];

  constructor() {
    super('WorkbenchScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string }) {
    this.onComplete = data.onComplete;
    this.cursorSpeed = 0.00015 + data.difficulty * 0.00002;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.perfectStreak = 0;
    this.combo = 0;

    // Set path type based on item category
    if (data.subCategoryId === 'GLOVES') {
      this.currentPathType = 'GLOVE';
    } else {
      this.currentPathType = 'WAVE';
    }
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
  }

  create() {
    this.root = this.add.container(0, 0);
    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.8).setOrigin(0.5);
    this.root.add(this.bgImage);
    this.progBg = this.add.rectangle(0, 0, 250, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg');
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '18px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);
    this.wavePathGraphics = this.add.graphics();
    this.root.add(this.wavePathGraphics);
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.9);
    this.root.add(this.cursor);
    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.root.add(this.comboText);
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);
    this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => { this.scale.off('resize', this.handleResize, this); });
    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;
      for (const node of this.targetNodes) { if (Phaser.Math.Distance.Between(p.x, p.y, node.x, node.y) < 60 * this.uiScale) { this.handleHit(node as any); } }
    });
    this.spawnNodes();
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width; const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.isPortrait = h > w;
    this.uiScale = this.isPortrait ? Phaser.Math.Clamp(h / 1000, 0.75, 1.2) : Phaser.Math.Clamp(w / 1200, 0.85, 1.3);
    this.centerX = w / 2; this.centerY = h / 2;
    this.bgImage.setPosition(this.centerX, this.centerY); this.bgImage.setDisplaySize(Math.max(w, h * 1.8), Math.max(h, w / 1.8));
    if (this.isPortrait) {
      const pbW = w * 0.8; this.progBg.setPosition(this.centerX, 80 * this.uiScale).setSize(pbW, 20 * this.uiScale);
      this.progressBar.setPosition(this.centerX - pbW / 2, 80 * this.uiScale);
      this.qualityText.setPosition(this.centerX, 120 * this.uiScale).setFontSize(Math.round(20 * this.uiScale));
    } else {
      const pbW = w * 0.5; this.progBg.setPosition(this.centerX, 40 * this.uiScale).setSize(pbW, 18 * this.uiScale);
      this.progressBar.setPosition(this.centerX - pbW / 2, 40 * this.uiScale);
      this.qualityText.setPosition(this.centerX, 80 * this.uiScale).setFontSize(Math.round(22 * this.uiScale));
    }
    this.updateProgressBar();
    this.waveStartX = w * 0.1; this.waveWidth = w * 0.8; this.waveAmplitude = (this.isPortrait ? 80 : 120) * this.uiScale;
    this.drawPath(); this.updateNodes();
  }

  private drawPath() {
    this.wavePathGraphics.clear().lineStyle(4, 0x3e2723, 0.8).beginPath();
    const steps = 400; const dashLen = 8; const gapLen = 6;
    let isDrawing = true; let counter = 0;
    for (let i = 0; i <= steps; i++) {
      const p = i / steps; const pos = this.getPathPosition(p);
      if (i === 0) { this.wavePathGraphics.moveTo(pos.x, pos.y); } else {
        if (isDrawing) { this.wavePathGraphics.lineTo(pos.x, pos.y); } else { this.wavePathGraphics.moveTo(pos.x, pos.y); }
      }
      counter++;
      if (isDrawing && counter >= dashLen) { isDrawing = false; counter = 0; } else if (!isDrawing && counter >= gapLen) { isDrawing = true; counter = 0; }
    }
    this.wavePathGraphics.strokePath();
  }

  private spawnNodes() {
    this.targetNodes.forEach((n) => n.destroy()); this.targetNodes = [];
    const segments = [[0.10, 0.22], [0.35, 0.47], [0.60, 0.72], [0.85, 0.95]];
    segments.forEach((range) => {
      const p = Phaser.Math.FloatBetween(range[0], range[1]);
      const node = this.add.circle(0, 0, 18, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981);
      (node as any).p = p; (node as any).hit = false; (node as any).missed = false;
      this.targetNodes.push(node); this.root.add(node);
    });
    this.updateNodes();
  }

  private updateNodes() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.targetNodes.forEach((n) => {
      const p = (n as any).p as number; const pos = this.getPathPosition(p);
      n.setPosition(pos.x, pos.y); n.setScale(this.uiScale);
    });
  }

  private getPathPosition(p: number) {
    if (this.currentPathType === 'GLOVE') {
      return this.getGlovePathPosition(p);
    }
    // Default Wave Path
    const x = this.waveStartX + p * this.waveWidth;
    const y = this.centerY + Math.sin(p * Math.PI * 4) * this.waveAmplitude;
    return { x, y };
  }

  private getGlovePathPosition(p: number) {
    const x = this.waveStartX + p * this.waveWidth;

    // Find the current segment in GLOVE_POINTS
    let segIdx = 0;
    for (let i = 0; i < this.GLOVE_POINTS.length - 1; i++) {
      if (p >= this.GLOVE_POINTS[i].x && p <= this.GLOVE_POINTS[i + 1].x) {
        segIdx = i;
        break;
      }
    }

    const p0 = this.GLOVE_POINTS[segIdx];
    const p1 = this.GLOVE_POINTS[segIdx + 1];

    // Linear interpolation between the two points
    const segmentProgress = (p - p0.x) / (p1.x - p0.x || 1);
    const normalizedY = p0.y + (p1.y - p0.y) * segmentProgress;

    const y = this.centerY + normalizedY * (this.isPortrait ? 200 : 300) * this.uiScale;

    return { x, y };
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.targetNodes.forEach((node: any) => {
      if (!node.hit && !node.missed && this.cursorProgress > node.p + 0.06) {
        node.missed = true; this.handleMiss(node.x, node.y);
      }
    });
    if (this.cursorProgress > 1) {
      this.cursorProgress = 0; this.confirmedProgress = Math.min(100, this.confirmedProgress + 25);
      this.updateProgressBar(); if (this.confirmedProgress >= 100) { this.finish(); return; }
      this.spawnNodes();
    }
    const pos = this.getPathPosition(this.cursorProgress); const nextPos = this.getPathPosition(this.cursorProgress + 0.005);
    const angle = Math.atan2(nextPos.y - pos.y, nextPos.x - pos.x);
    this.cursor.setPosition(pos.x, pos.y).setScale(this.uiScale * 0.3).setRotation(angle - Math.PI / 2);
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
  }

  private updateProgressBar() { const width = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, width); }

  private handleHit(node: any) {
    if (node.hit || node.missed) return;
    const diff = Math.abs(this.cursorProgress - node.p);
    if (diff < 0.045) { 
      node.hit = true; node.setFillStyle(0xfbbf24, 1).setStrokeStyle(3, 0xffffff); this.perfectStreak++; this.combo++;
      if (this.perfectStreak > 0 && this.perfectStreak % 8 === 0) { this.currentQuality += 1; }
      this.showFeedback('PERFECT!', 0xfbbf24, node.x, node.y); this.showCombo(node.x, node.y);
    } else if (diff < 0.09) { 
      node.hit = true; node.setFillStyle(0xe5e5e5, 0.8).setStrokeStyle(2, 0xaaaaaa); this.perfectStreak = 0; this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, node.x, node.y);
    }
  }

  private handleMiss(x: number, y: number) { this.perfectStreak = 0; this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5); this.showFeedback('MISS', 0xef4444, x, y); this.cameras.main.shake(100, 0.005); }

  private showCombo(x: number, y: number) {
      if (this.combo < 2) return;
      this.comboText.setPosition(x, y - 70 * this.uiScale).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(this.uiScale * 1.2);
      this.tweens.add({ targets: this.comboText, scale: this.uiScale, alpha: 0, duration: 800, ease: 'Power2' });
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const hex = '#' + color.toString(16).padStart(6, '0');
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(22 * this.uiScale)}px`, color: hex, stroke: '#000', strokeThickness: Math.round(5 * this.uiScale), fontStyle: 'bold' }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 50 * this.uiScale, alpha: 0, duration: 600, ease: 'Cubic.easeOut', onComplete: () => fb.destroy(), });
  }

  private finish() {
    this.isFinished = true; this.cursor.setVisible(false);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(bg); this.tweens.add({ targets: bg, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const textContent = this.isPortrait ? `${label}\nCRAFT!` : `${label} CRAFT!`;
    const fontSize = `${Math.round(this.isPortrait ? 36 * this.uiScale : 42 * this.uiScale)}px`;
    const txt = this.add.text(this.centerX, this.centerY, textContent, { fontFamily: 'Grenze Gotisch', fontSize: fontSize, color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 4, fontStyle: 'italic', align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);
    this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 500, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1200, () => { this.onComplete?.(this.currentQuality); }); } });
  }
}

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../data/equipment';
import { EquipmentCategory, EquipmentItem } from '../../../types/index';
import SmithingMinigame from './SmithingMinigame';
import WorkbenchMinigame from './WorkbenchMinigame';
import { Hammer, Shield, Sword, ChevronRight, Info, ChevronLeft, Lock, Check, X as XIcon, Box, Flame, ChevronDown, Heart, Star, Zap, Award, Wrench, X, ShoppingCart, Brain, AlertCircle, TrendingUp, Sparkles } from 'lucide-react';
import { useGame } from '../../../context/GameContext';
import { GAME_CONFIG } from '../../../config/game-config';
import { MASTERY_THRESHOLDS } from '../../../config/mastery-config';
import { MATERIALS } from '../../../data/materials';
import { getAssetUrl } from '../../../utils';

interface ForgeTabProps {
    onNavigate: (tab: any) => void;
}

const ForgeTab: React.FC<ForgeTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const { inventory, stats, isCrafting, craftingMastery, activeEvent, unlockedRecipes } = state;
  const { hasFurnace, hasWorkbench } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [hasPromptedFurnace, setHasPromptedFurnace] = useState(false);
  const [failedFuelHighlight, setFailedFuelHighlight] = useState(false);

  const [expandedSubCat, setExpandedSubCat] = useState<string | null>(null);
  const [favorites, setFavorites] = useState<string[]>([]);

  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  const getInventoryCount = useCallback((id: string) => {
      return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const getResourceName = (id: string) => {
      const itemDef = Object.values(MATERIALS).find(i => i.id === id);
      return itemDef ? itemDef.name : id;
  };

  const getItemImageUrl = (item: EquipmentItem) => {
    if (item.image) return getAssetUrl(item.image);
    return getAssetUrl(`${item.id}.png`);
  };

  const GLOBAL_COOLING_RATE_PER_SEC = 5; 
  const timeDiffSec = (Date.now() - (state.lastForgeTime || 0)) / 1000;
  const coolingAmount = timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC;
  const currentResidualTemp = Math.max(0, (state.forgeTemperature || 0) - coolingAmount);

  const hasHeat = currentResidualTemp > 0;
  const charcoalCount = getInventoryCount('charcoal');
  const hasFuel = charcoalCount > 0;

  useEffect(() => {
    if (!hasFurnace && !hasPromptedFurnace && !activeEvent) {
        actions.triggerEvent({
            id: 'CUSTOMER_VISIT',
            title: "The Forge lies in Ruins",
            description: "Your journey as a blacksmith starts with a single spark. To begin forging weapons and armor, you must first install a Furnace from the market.",
            options: [
                { label: "Visit Market (500 G)", action: () => onNavigate('MARKET') },
                { label: "I'll look around first", action: () => {} }
            ]
        });
        setHasPromptedFurnace(true);
    }
  }, [hasFurnace, hasPromptedFurnace, activeEvent, actions, onNavigate]);

  const canEnterForge = useMemo(() => {
      if (!selectedItem) return false;
      if (selectedItem.craftingType === 'WORKBENCH') return true;
      return hasFuel || hasHeat;
  }, [selectedItem, hasFuel, hasHeat]);

  const requiredEnergy = useMemo(() => {
      if (!selectedItem) return GAME_CONFIG.ENERGY_COST.CRAFT;
      const count = craftingMastery[selectedItem.id] || 0;
      if (count >= MASTERY_THRESHOLDS.ARTISAN) {
          return GAME_CONFIG.ENERGY_COST.CRAFT - MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
      }
      return GAME_CONFIG.ENERGY_COST.CRAFT;
  }, [selectedItem, craftingMastery]);

  const hasEnergy = stats.energy >= requiredEnergy;

  const canAffordResources = useCallback((item: EquipmentItem) => {
      return item.requirements.every(req => getInventoryCount(req.id) >= req.count);
  }, [getInventoryCount]);

  const visibleItems = useMemo(() => {
      return EQUIPMENT_ITEMS.filter(item => {
          const isUnlocked = item.unlockedByDefault !== false || unlockedRecipes?.includes(item.id);
          if (!isUnlocked) return false;
          if (item.tier > stats.tierLevel) return false;
          const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
          return subCatDef?.categoryId === activeCategory;
      });
  }, [activeCategory, stats.tierLevel, unlockedRecipes]);

  const groupedItems = useMemo(() => {
      const groups: Record<string, EquipmentItem[]> = {};
      visibleItems.forEach(item => {
          if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
          groups[item.subCategoryId].push(item);
      });
      return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
      return EQUIPMENT_SUBCATEGORIES.filter(sc => 
          sc.categoryId === activeCategory && groupedItems[sc.id] && groupedItems[sc.id].length > 0
      );
  }, [activeCategory, groupedItems]);

  useEffect(() => {
      if (visibleSubCats.length > 0 && !expandedSubCat) {
          setExpandedSubCat(visibleSubCats[0].id);
      }
  }, [activeCategory, visibleSubCats, expandedSubCat]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);   
  }, []);

  const toggleSubCategory = useCallback((subCatId: string) => {
      setExpandedSubCat(prev => (prev === subCatId ? null : subCatId));
  }, []);

  const toggleFavorite = useCallback((e: React.MouseEvent, itemId: string) => {
      e.stopPropagation(); 
      setFavorites(prev => prev.includes(itemId) ? prev.filter(id => id !== itemId) : [...prev, itemId]);
  }, []);

  const startCrafting = useCallback(() => {
      if (!selectedItem) return;
      if (selectedItem.craftingType === 'FORGE' && !canEnterForge) {
          setFailedFuelHighlight(true);
          setTimeout(() => setFailedFuelHighlight(false), 2000);
          return;
      }
      actions.startCrafting(selectedItem);
      setIsPanelOpen(false); 
  }, [actions, selectedItem, canEnterForge]);

  const cancelCrafting = useCallback(() => {
      if (selectedItem) actions.cancelCrafting(selectedItem);
      else actions.setCrafting(false); 
      setIsPanelOpen(true);
  }, [actions, selectedItem]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) actions.finishCrafting(selectedItem, score, bonus);
    setIsPanelOpen(true);
  }, [selectedItem, actions]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      updateTooltipPosition(e.clientX, e.clientY);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) updateTooltipPosition(e.clientX, e.clientY);
  }, [hoveredItem]);

  const updateTooltipPosition = (x: number, y: number) => {
      const viewportW = window.innerWidth;
      const viewportH = window.innerHeight;
      let finalX = x + 20;
      let finalY = y + 20;
      if (finalX + 240 > viewportW) finalX = x - 260;
      if (finalY + 160 > viewportH) finalY = y - 180;
      setTooltipPos({ x: finalX, y: finalY });
  };

  const handleMouseLeave = useCallback(() => setHoveredItem(null), []);

  const renderStats = (item: EquipmentItem) => {
    if (!item.baseStats) return null;
    const s = item.baseStats;
    return (
        <div className="grid grid-cols-2 gap-1.5 md:gap-3 w-full max-w-xs mb-4 md:mb-6 animate-in slide-in-from-bottom-2 duration-500">
            {s.physicalAttack > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Sword className="w-2.5 h-2.5" /> P.Atk</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.physicalAttack}</span>
                </div>
            )}
            {s.magicalAttack > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Zap className="w-2.5 h-2.5" /> M.Atk</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.magicalAttack}</span>
                </div>
            )}
            {s.physicalDefense > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Shield className="w-2.5 h-2.5" /> P.Def</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.physicalDefense}</span>
                </div>
            )}
            {s.magicalDefense > 0 && (
                <div className="bg-stone-900/60 border border-stone-800 p-1.5 md:p-2 rounded-lg flex justify-between items-center shadow-inner">
                    <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase flex items-center gap-1"><Brain className="w-2.5 h-2.5" /> M.Def</span>
                    <span className="text-[9px] md:text-sm font-mono font-bold text-stone-200">{s.magicalDefense}</span>
                </div>
            )}
        </div>
    );
  };

  const renderMasteryProgress = (item: EquipmentItem) => {
    const count = craftingMastery[item.id] || 0;
    let nextThreshold = MASTERY_THRESHOLDS.ADEPT;
    let label = "Novice";
    let color = "from-stone-500 to-stone-400";
    if (count >= MASTERY_THRESHOLDS.ARTISAN) { nextThreshold = 50; label = "Artisan"; color = "from-amber-600 to-amber-400 shadow-[0_0_10px_rgba(245,158,11,0.3)]"; }
    else if (count >= MASTERY_THRESHOLDS.ADEPT) { nextThreshold = MASTERY_THRESHOLDS.ARTISAN; label = "Adept"; color = "from-emerald-600 to-emerald-400"; }
    const progress = Math.min(100, (count / nextThreshold) * 100);
    return (
        <div className="w-full max-w-xs mb-6 md:mb-8 bg-stone-900/40 p-2 md:p-3 rounded-xl border border-stone-800/50">
            <div className="flex justify-between items-end mb-1.5">
                <div className="flex items-center gap-1.5"><Award className="w-3 h-3 md:w-4 md:h-4 text-amber-500" /><span className="text-[8px] md:text-[10px] font-black uppercase tracking-widest text-stone-400">{label} Mastery</span></div>
                <span className="text-[8px] md:text-[10px] font-mono font-bold text-stone-500">{count} / {nextThreshold} CRAFTS</span>
            </div>
            <div className="w-full h-1 md:h-1.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800 shadow-inner">
                <div className={`h-full bg-gradient-to-r ${color} transition-all duration-1000`} style={{ width: `${progress}%` }}></div>
            </div>
        </div>
    );
  };

  const isRequirementMet = useMemo(() => {
    if (!selectedItem) return true;
    if (selectedItem.craftingType === 'FORGE') return hasFurnace;
    if (selectedItem.craftingType === 'WORKBENCH') return hasWorkbench;
    return true;
  }, [selectedItem, hasFurnace, hasWorkbench]);

  const renderItemCard = (item: EquipmentItem) => {
      const isSelected = selectedItem?.id === item.id;
      const isFav = favorites.includes(item.id);
      const count = inventory.filter(i => i.name === item.name).length;
      return (
        <div 
            key={item.id} onClick={() => setSelectedItem(item)}
            onMouseEnter={(e) => handleMouseEnter(item, e)} onMouseMove={handleMouseMove} onMouseLeave={handleMouseLeave}
            className={`relative flex flex-col items-center rounded-lg border transition-all cursor-pointer group text-left h-[115px] md:h-[130px] overflow-hidden ${isSelected ? 'bg-amber-900/20 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.2)]' : 'bg-stone-800 border-stone-700 hover:border-stone-500 hover:bg-stone-750'}`}
        >
            <div className="w-full flex justify-between items-start p-1.5 md:p-2 z-10">
                 <span className={`text-[8px] md:text-[10px] font-bold tracking-wider font-mono ${isSelected ? 'text-amber-400' : 'text-stone-600'}`}>T{item.tier}</span>
                 <button onClick={(e) => toggleFavorite(e, item.id)} className="p-1 rounded-full hover:bg-stone-700 transition-colors"><Heart className={`w-3 h-3 md:w-3.5 md:h-3.5 ${isFav ? 'fill-red-500 text-red-500' : 'text-stone-600 hover:text-stone-400'}`} /></button>
            </div>
            <div className="flex-1 flex items-center justify-center group-hover:scale-110 transition-transform -mt-2"><img src={getItemImageUrl(item)} className="w-8 h-8 md:w-10 md:h-10 object-contain drop-shadow-md" /></div>
            <div className="w-full text-center pb-1.5 px-1 flex flex-col items-center gap-0.5"><div className={`text-[10px] md:text-xs font-bold leading-tight truncate w-full ${isSelected ? 'text-amber-200' : 'text-stone-300'}`}>{item.name}</div>{count > 0 && <div className="inline-flex items-center gap-0.5 bg-stone-950/50 px-1.5 py-0.5 rounded text-[8px] font-mono text-stone-500 border border-stone-800/50"><Box className="w-2 h-2" /> {count}</div>}</div>
        </div>
      );
  };

  // --- Mastery Radial Logic ---
  const masteryInfo = useMemo(() => {
    if (!selectedItem) return null;
    const count = craftingMastery[selectedItem.id] || 0;
    let label = "Novice";
    let colorClass = "stroke-stone-500";
    let glowClass = "shadow-[0_0_20px_rgba(120,113,108,0.2)]";
    let progress = 0;
    let nextMax = MASTERY_THRESHOLDS.ADEPT;

    if (count >= MASTERY_THRESHOLDS.ARTISAN) {
      label = "Artisan";
      colorClass = "stroke-amber-500";
      glowClass = "shadow-[0_0_40px_rgba(245,158,11,0.3)]";
      progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
      nextMax = 50; 
    } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
      label = "Adept";
      colorClass = "stroke-emerald-500";
      glowClass = "shadow-[0_0_30px_rgba(16,185,129,0.2)]";
      progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
      nextMax = MASTERY_THRESHOLDS.ARTISAN;
    } else {
      label = "Novice";
      colorClass = "stroke-stone-400";
      glowClass = "shadow-[0_0_20px_rgba(168,162,158,0.15)]";
      progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
      nextMax = MASTERY_THRESHOLDS.ADEPT;
    }

    const radius = 46;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    return { label, colorClass, glowClass, progress, circumference, offset, count, nextMax };
  }, [selectedItem, craftingMastery]);

  const content = useMemo(() => {
    const canCraft = selectedItem && canAffordResources(selectedItem) && (selectedItem.craftingType === 'WORKBENCH' || canEnterForge) && hasEnergy && isRequirementMet;
    const isMissingFuelOnly = selectedItem && selectedItem.craftingType === 'FORGE' && canAffordResources(selectedItem) && !canEnterForge && hasEnergy && isRequirementMet;

    return (
        <div className="relative h-full w-full bg-stone-950 overflow-hidden" style={{ backgroundImage: `url(${getAssetUrl('tile_forge.png')})`, backgroundRepeat: 'repeat', backgroundBlendMode: 'multiply' }}>
        {selectedItem && !isRequirementMet && (
            <div className="absolute inset-0 z-[60] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-stone-950/90 backdrop-blur-md animate-in fade-in duration-700"></div>
                <div className="relative z-10 p-6 md:p-8 max-w-md w-full bg-stone-900 border-2 border-stone-800 rounded-2xl shadow-2xl flex flex-col items-center text-center animate-in zoom-in-95 duration-500 max-h-[90vh] overflow-y-auto">
                    <button onClick={() => setSelectedItem(null)} className="absolute top-4 right-4 p-2 text-stone-500 hover:text-stone-300 transition-colors"><X className="w-5 h-5" /></button>
                    <div className="w-16 h-16 md:w-20 md:h-20 bg-stone-800 rounded-full flex items-center justify-center mb-4 md:mb-6 border border-stone-700 shrink-0">{selectedItem.craftingType === 'FORGE' ? <Flame className="w-8 h-8 md:w-10 md:h-10 text-stone-600" /> : <Wrench className="w-8 h-8 md:w-10 md:h-10 text-stone-600" />}</div>
                    <h2 className="text-xl md:text-2xl font-bold text-stone-300 font-serif mb-2">{selectedItem.craftingType === 'FORGE' ? 'Furnace Required' : 'Workbench Required'}</h2>
                    <p className="text-sm md:text-base text-stone-500 mb-6 md:mb-8 leading-relaxed">Crafting <span className="text-amber-500 font-bold">{selectedItem.name}</span> requires a functional {selectedItem.craftingType === 'FORGE' ? 'furnace' : 'workbench'}. Visit the market to purchase one.</p>
                    <button onClick={() => onNavigate('MARKET')} className="w-full py-3 md:py-4 bg-amber-700 hover:bg-amber-600 text-amber-50 font-bold rounded-xl shadow-lg hover:shadow-amber-900/40 transition-all flex items-center justify-center gap-2 group shrink-0">Go to Market <ChevronRight className="w-4 h-4 md:w-5 md:h-5 group-hover:translate-x-1 transition-transform" /></button>
                </div>
            </div>
        )}
        <div className={`absolute inset-0 z-0 flex w-full h-full ${((selectedItem && !isRequirementMet) || !hasFurnace) ? 'blur-sm pointer-events-none' : ''}`}>
            <div className={`h-full relative flex flex-col transition-all duration-500 ease-in-out ${isPanelOpen ? 'w-[55%] md:w-[60%]' : 'w-full'}`}>
                <div className="w-full h-full flex flex-col items-center justify-center p-4 md:p-8 bg-stone-925/40 relative overflow-hidden">
                    <div className="absolute inset-0 opacity-10 pointer-events-none flex items-center justify-center">{selectedItem?.craftingType === 'FORGE' ? <Hammer className="w-64 h-64 md:w-96 md:h-96 text-stone-500" /> : <Wrench className="w-64 h-64 md:w-96 md:h-96 text-stone-500" />}</div>
                    {selectedItem ? (
                        <div className="z-10 flex flex-col items-center animate-in fade-in zoom-in duration-300 w-full max-w-lg">

                            {/* NEW: Mastery Radial Indicator around item image */}
                            <div className="relative mb-3 md:mb-6 group">
                                <div className={`w-24 h-24 md:w-48 md:h-48 bg-stone-900 rounded-full flex items-center justify-center relative z-10 p-2 md:p-4 border border-stone-800/50 ${masteryInfo?.glowClass} transition-all duration-700`}>
                                    {/* Radial SVG Gauge */}
                                    <svg className="absolute inset-0 w-full h-full -rotate-90 pointer-events-none" viewBox="0 0 100 100">
                                        {/* Background Track */}
                                        <circle cx="50" cy="50" r="46" stroke="currentColor" strokeWidth="4" fill="transparent" className="text-stone-950/40" />
                                        {/* Progress Arc */}
                                        <circle 
                                            cx="50" cy="50" r="46" 
                                            stroke="currentColor" strokeWidth="4" fill="transparent"
                                            strokeDasharray={masteryInfo?.circumference}
                                            strokeDashoffset={masteryInfo?.offset}
                                            strokeLinecap="round"
                                            className={`${masteryInfo?.colorClass} transition-all duration-1000 ease-out`}
                                        />
                                    </svg>
                                    <img src={getItemImageUrl(selectedItem)} className="w-14 h-14 md:w-32 md:h-32 object-contain drop-shadow-2xl z-20 relative transform group-hover:scale-110 transition-transform duration-500" />

                                    {/* Small Rank Badge */}
                                    <div className={`absolute -bottom-1 -right-1 md:bottom-2 md:right-2 z-30 px-1.5 py-0.5 md:px-2.5 md:py-1 rounded-full border border-stone-700 bg-stone-900 shadow-xl flex items-center gap-1 animate-in slide-in-from-right-2 duration-700`}>
                                        <Star className={`w-2 h-2 md:w-3 md:h-3 ${masteryInfo?.colorClass.replace('stroke-', 'fill-')}`} />
                                        <span className={`text-[7px] md:text-[10px] font-black uppercase tracking-tighter ${masteryInfo?.colorClass.replace('stroke-', 'text-')}`}>{masteryInfo?.label}</span>
                                    </div>
                                </div>
                            </div>

                            <h2 className="text-xl md:text-3xl font-bold text-amber-500 mb-1 md:mb-1.5 font-serif tracking-wide">{selectedItem.name}</h2>
                            <p className="text-stone-500 text-center max-w-md mb-4 md:mb-6 italic text-[9px] md:text-sm leading-tight px-6">"{selectedItem.description}"</p>

                            {/* REINSTATED: Stats Block */}
                            {renderStats(selectedItem)}

                            {/* Modified Mastery Info (Simplified Text since circle handles visual) */}
                            <div className="w-full max-w-xs mb-6 md:mb-8 flex flex-col items-center">
                                <div className="flex items-center gap-1.5 text-[8px] md:text-[10px] font-black uppercase tracking-widest text-stone-500 mb-1">
                                    <Award className="w-3 h-3 md:w-4 md:h-4 text-amber-600" />
                                    <span>Experience: {masteryInfo?.count} / {masteryInfo?.nextMax}</span>
                                </div>
                            </div>

                            <div className="relative group flex flex-col items-center">
                                {/* Persistent Fuel Warning */}
                                {isMissingFuelOnly && (
                                    <div className="mb-4 flex items-center gap-1.5 text-orange-500 font-bold text-[9px] md:text-xs animate-pulse bg-orange-950/30 px-3 py-1 rounded-full border border-orange-900/40">
                                        <Flame className="w-3 h-3 md:w-4 md:h-4" />
                                        <span>Fuel Required to Heat the Forge</span>
                                    </div>
                                )}

                                <button 
                                    onClick={startCrafting} 
                                    disabled={!canAffordResources(selectedItem) || !hasEnergy || !isRequirementMet} 
                                    className={`px-8 md:px-12 py-3 md:py-4 rounded-lg font-black text-sm md:text-lg shadow-lg transition-all transform hover:-translate-y-1 flex items-center gap-2 md:gap-3 border ${failedFuelHighlight ? 'bg-red-900 border-red-500 animate-shake-hard shadow-[0_0_20px_rgba(239,68,68,0.4)]' : canCraft ? (selectedItem.craftingType === 'FORGE' ? 'bg-amber-700 hover:bg-amber-600 border-amber-500' : 'bg-emerald-700 hover:bg-emerald-600 border-emerald-500') : (isMissingFuelOnly ? 'bg-stone-800 text-stone-300 border-amber-600/50' : 'bg-stone-800 text-stone-500 border-stone-700 opacity-70')}`}
                                >
                                    {selectedItem.craftingType === 'FORGE' ? <Hammer className="w-4 h-4 md:w-6 md:h-6" /> : <Wrench className="w-4 h-4 md:w-6 md:h-6" />}
                                    <span>{selectedItem.craftingType === 'FORGE' ? 'Start Forging' : 'Start Crafting'}</span>
