    { x: 0.44, y: -0.33 }, // middle tip
    { x: 0.52, y: 0.02 }, // between middle-ring
    { x: 0.62, y: -0.25 }, // ring tip
    { x: 0.70, y: 0.05 }, // between ring-pinky
    { x: 0.80, y: -0.10 }, // pinky tip
    { x: 0.90, y: 0.20 }, // outer hand
    { x: 0.95, y: 0.45 }, // wrist bottom R
    { x: 0.72, y: 0.50 }, // wrist bottom curve 1
