    <div className="absolute inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in duration-1000 overflow-hidden">
      <div className="relative z-10 p-5 md:p-10 max-w-md w-full max-h-[95vh] flex flex-col items-center text-center animate-in zoom-in-95 duration-700 overflow-y-auto custom-scrollbar">

        {/* Close Button - Top Right */}
        <button 
            onClick={actions.closeRest}
            className="absolute top-4 right-4 p-2 bg-stone-900/50 hover:bg-stone-800 rounded-full text-stone-500 hover:text-stone-300 transition-colors z-20 border border-stone-800"
            title="Cancel"
        >
            <X className="w-5 h-5" />
        </button>

        <div className="relative mb-4 md:mb-6 shrink-0 hidden xs:block">
            <div className="absolute inset-0 bg-indigo-500/30 blur-2xl rounded-full"></div>
            <div className="w-16 h-16 md:w-20 md:h-20 bg-indigo-950 rounded-full flex items-center justify-center border-2 border-indigo-500/50 shadow-[0_0_30px_rgba(99,102,241,0.3)] relative z-10">
                <Moon className="w-8 h-8 md:w-10 md:h-10 text-indigo-300" />
            </div>
        </div>

        <h2 className="text-2xl md:text-3xl font-bold text-indigo-100 font-serif mb-1 md:mb-2 tracking-wide shrink-0">End of Day Report</h2>
        <p className="text-indigo-200/60 mb-6 md:mb-8 text-xs md:text-sm font-light shrink-0 uppercase tracking-[0.2em]">
            Financial Audit • Day {state.stats.day}
        </p>

        {/* Financial Summary Card */}
        <div className="w-full bg-indigo-950/50 border border-indigo-800/50 rounded-xl p-4 md:p-6 mb-6 md:mb-8 space-y-2 shadow-inner shrink-0 text-left">

            <div className="border-b border-indigo-800/50 pb-2 mb-2">
                <div className="flex justify-between items-center mb-1">
                    <span className="text-emerald-400 font-black text-[10px] md:text-xs uppercase tracking-widest">Revenue</span>
                    <span className="text-emerald-400 font-mono font-bold">+{totalIncome} G</span>
                </div>
                <FinancialRow label="Shop Sales" value={dailyFinancials.incomeShop} icon={Coins} isSub />
                <FinancialRow label="Inventory Sales" value={dailyFinancials.incomeInventory} icon={Package} isSub />
                <FinancialRow label="Dungeon Rewards" value={dailyFinancials.incomeDungeon} icon={Map} isSub />
                <FinancialRow label="Cold Repairs" value={dailyFinancials.incomeRepair} icon={Wrench} isSub />
            </div>

            <div className="border-b border-indigo-800/50 pb-2 mb-2">
                <div className="flex justify-between items-center mb-1">
                    <span className="text-red-400 font-black text-[10px] md:text-xs uppercase tracking-widest">Expenses</span>
                    <span className="text-red-400 font-mono font-bold">-{totalExpenses} G</span>
                </div>
                <FinancialRow label="Market Purchases" value={dailyFinancials.expenseMarket} icon={ShoppingBag} isNegative isSub />
                <FinancialRow label="Mercenary Wages" value={totalWages} icon={Users} isNegative isSub />
            </div>

            <div className="flex justify-between items-center pt-2">
                <span className="text-indigo-100 font-black uppercase text-xs md:text-sm tracking-tighter">Net Profit</span>
                <span className={`font-mono font-bold text-base md:text-xl ${netChange >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
