import React, { createContext, useContext, useReducer, useMemo, useEffect, useRef } from 'react';
import { GameContextType, GameState } from '../types/index';
import { gameReducer } from '../state/gameReducer';
import { createInitialGameState } from '../state/initial-game-state';
import { EquipmentItem, EquipmentSlotType } from '../types/inventory';
import { ShopCustomer } from '../types/shop';
import { Mercenary } from '../models/Mercenary';
import { PrimaryStats } from '../models/Stats';
import { GAME_CONFIG } from '../config/game-config';
import { getEnergyCost } from '../utils/craftingLogic';
import { GameEvent } from '../types/events';
import { saveToSlot } from '../utils/saveSystem';

const GameContext = createContext<GameContextType | undefined>(undefined);

export const useGame = () => {
  const context = useContext(GameContext);
  if (context === undefined) {
    throw new Error('useGame must be used within a GameProvider');
  }
  return context;
};

interface GameProviderProps {
    initialSlotIndex?: number;
    children: React.ReactNode;
}

export const GameProvider: React.FC<GameProviderProps> = ({ children, initialSlotIndex = 0 }) => {
  const [state, dispatch] = useReducer(gameReducer, undefined, createInitialGameState);

  const currentSlotRef = useRef(initialSlotIndex);

  const stateRef = useRef(state);
  useEffect(() => {
    stateRef.current = state;
  }, [state]);

  const prevDayRef = useRef(state.stats.day);
  useEffect(() => {
    if (state.stats.day === prevDayRef.current + 1) {
      saveToSlot(currentSlotRef.current, state);
    }
    prevDayRef.current = state.stats.day;
  }, [state.stats.day, state]);

  const triggerEnergyHighlight = () => {
      dispatch({ type: 'SET_UI_EFFECT', payload: { effect: 'energyHighlight', value: true } });
      setTimeout(() => {
          dispatch({ type: 'SET_UI_EFFECT', payload: { effect: 'energyHighlight', value: false } });
      }, 3000);
  };

  const showToast = (message: string) => {
      dispatch({ type: 'SHOW_TOAST', payload: message });
      setTimeout(() => {
          dispatch({ type: 'HIDE_TOAST' });
      }, 3000);
  };

  const actions = useMemo(() => ({
    repairItem: () => {
        if (stateRef.current.stats.energy < GAME_CONFIG.ENERGY_COST.REPAIR) {
            triggerEnergyHighlight();
            return;
        }
        dispatch({ type: 'REPAIR_WORK' });
    },
    rest: () => dispatch({ type: 'SLEEP' }),
    confirmSleep: () => dispatch({ type: 'CONFIRM_SLEEP' }),
    category: () => dispatch({ type: 'CLOSE_SLEEP_MODAL' }), // Note: Fix typo if intended, kept as per source
    closeRest: () => dispatch({ type: 'CLOSE_SLEEP_MODAL' }),

    triggerEvent: (event: GameEvent) => dispatch({ type: 'TRIGGER_EVENT', payload: event }),
    handleEventOption: (action: () => void) => {
      action();
      dispatch({ type: 'CLOSE_EVENT' });
    },
    closeEvent: () => dispatch({ type: 'CLOSE_EVENT' }),

    saveGame: (slotIndex?: number) => {
        const targetSlot = slotIndex !== undefined ? slotIndex : currentSlotRef.current;
        const success = saveToSlot(targetSlot, stateRef.current);
        if (success) {
            currentSlotRef.current = targetSlot;
            showToast(`Progress saved to Slot ${targetSlot + 1}.`);
        }
    },
    loadGame: (loadedState: GameState) => {
        dispatch({ type: 'LOAD_GAME', payload: loadedState });
    },

    startCrafting: (item: EquipmentItem) => {
        const masteryCount = stateRef.current.craftingMastery[item.id] || 0;
        const energyCost = getEnergyCost(item, masteryCount);
        if (stateRef.current.stats.energy < energyCost) {
            triggerEnergyHighlight();
            return;
        }
        dispatch({ type: 'START_CRAFTING', payload: { item } });
    },
    cancelCrafting: (item: EquipmentItem) => dispatch({ type: 'CANCEL_CRAFTING', payload: { item } }),
    finishCrafting: (item: EquipmentItem, quality: number, bonus?: number) => dispatch({ type: 'FINISH_CRAFTING', payload: { item, quality, bonus } }),
    craftItem: (item: EquipmentItem, quality: number) => dispatch({ type: 'FINISH_CRAFTING', payload: { item, quality } }),
    dismissCraftingResult: () => dispatch({ type: 'DISMISS_CRAFTING_RESULT' }),

    buyItems: (items: { id: string; count: number }[], totalCost: number) => dispatch({ type: 'BUY_MARKET_ITEMS', payload: { items, totalCost } }),
    sellItem: (itemId: string, count: number, price: number, equipmentInstanceId?: string, customer?: Mercenary) =>
        dispatch({ type: 'SELL_ITEM', payload: { itemId, count, price, equipmentInstanceId, customer } }),
    toggleShop: () => {
        if (!stateRef.current.forge.isShopOpen && stateRef.current.stats.energy < GAME_CONFIG.ENERGY_COST.OPEN_SHOP) {
            triggerEnergyHighlight();
            return;
        }
        dispatch({ type: 'TOGGLE_SHOP' });
    },
    addMercenary: (merc: Mercenary) => dispatch({ type: 'ADD_KNOWN_MERCENARY', payload: merc }),
    scoutMercenary: (merc: Mercenary, cost: number) => dispatch({ type: 'SCOUT_MERCENARY', payload: { mercenary: merc, cost } }),

    consumeItem: (id: string, count: number) => dispatch({ type: 'PAY_COST', payload: { items: [{ id, count }] } }),

    enqueueCustomer: (customer: ShopCustomer) => dispatch({ type: 'ENQUEUE_CUSTOMER', payload: customer }),
    nextCustomer: () => dispatch({ type: 'NEXT_CUSTOMER' }),
    dismissCustomer: () => dispatch({ type: 'DISMISS_CUSTOMER' }),

    setCrafting: (isCrafting: boolean) => dispatch({ type: 'SET_CRAFTING', payload: isCrafting }),
    updateForgeStatus: (temp: number) => dispatch({ type: 'UPDATE_FORGE_STATUS', payload: { temp } }),
    updateMercenaryStats: (mercenaryId: string, stats: PrimaryStats) => dispatch({ type: 'UPDATE_MERCENARY_STATS', payload: { mercenaryId, stats } }),
    toggleJournal: () => dispatch({ type: 'TOGGLE_JOURNAL' }),

    hireMercenary: (mercenaryId: string, cost: number) => dispatch({ type: 'HIRE_MERCENARY', payload: { mercenaryId, cost } }),
    fireMercenary: (mercenaryId: string) => dispatch({ type: 'FIRE_MERCENARY', payload: { mercenaryId } }),
    giveGift: (mercenaryId: string, itemId: string) => dispatch({ type: 'GIVE_GIFT', payload: { mercenaryId, itemId } }),
    talkMercenary: (mercenaryId: string) => dispatch({ type: 'TALK_MERCENARY', payload: { mercenaryId } }),

    startExpedition: (dungeonId: string, partyIds: string[]) => dispatch({ type: 'START_EXPEDITION', payload: { dungeonId, partyIds } }),
    completeExpedition: (expeditionId: string) => dispatch({ type: 'COMPLETE_EXPEDITION', payload: { expeditionId } }),
    claimExpedition: (expeditionId: string) => dispatch({ type: 'CLAIM_EXPEDITION', payload: { expeditionId } }),
    dismissDungeonResult: () => dispatch({ type: 'DISMISS_DUNGEON_RESULT' }),

    equipItem: (mercenaryId: string, inventoryItemId: string) => dispatch({ type: 'EQUIP_ITEM', payload: { mercenaryId, inventoryItemId } }),
    unequipItem: (mercenaryId: string, slot: EquipmentSlotType) => dispatch({ type: 'UNEQUIP_ITEM', payload: { mercenaryId, slot } }),

    useItem: (itemId: string) => dispatch({ type: 'USE_ITEM', payload: { itemId } }),
    allocateStat: (mercenaryId: string, stat: keyof PrimaryStats) => dispatch({ type: 'ALLOCATE_STAT', payload: { mercenaryId, stat } }),

    startManualAssault: (dungeonId: string, partyIds: string[]) => 
        dispatch({ type: 'START_MANUAL_DUNGEON', payload: { dungeonId, partyIds } }),
    moveInManualDungeon: (dx: number, dy: number) => 
        dispatch({ type: 'MOVE_MANUAL_DUNGEON', payload: { x: dx, y: dy } }),
    finishManualAssault: () =>
        dispatch({ type: 'FINISH_MANUAL_DUNGEON' }),
    retreatFromManualDungeon: () => 
        dispatch({ type: 'RETREAT_MANUAL_DUNGEON' }),

    toggleManualDungeonOverlay: (show: boolean) => 
        dispatch({ type: 'TOGGLE_MANUAL_DUNGEON_OVERLAY', payload: show }),

    rescueMercenary: (npcId: string) => 
        dispatch({ type: 'RESCUE_NPC', payload: { npcId } }),

    triggerEnergyHighlight,
    showToast,
    hideToast: () => dispatch({ type: 'HIDE_TOAST' })
  }), []); 

  return (
    <GameContext.Provider value={{ state, actions }}>
      {children}
    </GameContext.Provider>
  );
};

export { GameContext };

import { GameState } from '../../types/index';
import { Mercenary } from '../../models/Mercenary';
import { DUNGEON_CONFIG } from '../../config/dungeon-config';
import { PrimaryStats, mergePrimaryStats, calculateMaxHp, calculateMaxMp } from '../../models/Stats';
import { EquipmentRarity } from '../../models/Equipment';

export const handleAddKnownMercenary = (state: GameState, merc: Mercenary): GameState => {
    if (state.knownMercenaries.some(m => m.id === merc.id)) return state;
    const mercWithData = { 
        ...merc, 
        expeditionEnergy: merc.expeditionEnergy ?? DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
        currentXp: merc.currentXp ?? 0,
        xpToNextLevel: merc.xpToNextLevel ?? (merc.level * 100),
        status: 'VISITOR' as const
    };
    return {
        ...state,
        knownMercenaries: [...state.knownMercenaries, mercWithData],
        logs: [`${merc.name} is now a regular at the tavern.`, ...state.logs]
    };
};

export const handleScoutMercenary = (state: GameState, payload: { mercenary: Mercenary; cost: number }): GameState => {
    const { mercenary, cost } = payload;
    if (state.stats.gold < cost) return state;

    const mercWithData = { 
        ...mercenary, 
        expeditionEnergy: mercenary.expeditionEnergy ?? DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
        currentXp: mercenary.currentXp ?? 0,
        xpToNextLevel: mercenary.xpToNextLevel ?? (mercenary.level * 100),
        status: 'VISITOR' as const
    };

    return {
        ...state,
        stats: {
            ...state.stats,
            gold: state.stats.gold - cost,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                expenseScout: state.stats.dailyFinancials.expenseScout + cost
            }
        },
        knownMercenaries: [...state.knownMercenaries, mercWithData],
        logs: [`Paid ${cost} G to find new talent. ${mercenary.name} arrived at the tavern.`, ...state.logs]
    };
};

export const handleHireMercenary = (state: GameState, payload: { mercenaryId: string; cost: number }): GameState => {
    const { mercenaryId, cost } = payload;
    if (state.stats.gold < cost) return state;
    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (m.id === mercenaryId) return { ...m, status: 'HIRED' as const };
        return m;
    });
    const hiredMerc = updatedMercenaries.find(m => m.id === mercenaryId);
    const name = hiredMerc ? hiredMerc.name : 'Mercenary';
    return {
        ...state,
        stats: { 
            ...state.stats, 
            gold: state.stats.gold - cost,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                expenseScout: state.stats.dailyFinancials.expenseScout + cost
            }
        },
        knownMercenaries: updatedMercenaries,
        logs: [`Contract signed! ${name} has joined your service. -${cost} G`, ...state.logs]
    };
};

export const handleFireMercenary = (state: GameState, payload: { mercenaryId: string }): GameState => {
    const { mercenaryId } = payload;
    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (m.id === mercenaryId) return { ...m, status: 'VISITOR' as const };
        return m;
    });
    const firedMerc = updatedMercenaries.find(m => m.id === mercenaryId);
    const name = firedMerc ? firedMerc.name : 'Mercenary';
    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        logs: [`Contract terminated. ${name} is no longer in your service.`, ...state.logs]
    };
};

export const handleGiveGift = (state: GameState, payload: { mercenaryId: string; itemId: string }): GameState => {
    const { mercenaryId, itemId } = payload;
    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const inventoryItem = state.inventory.find(i => i.id === itemId);
    if (!inventoryItem || inventoryItem.quantity <= 0) return state;

    const mercenary = { ...state.knownMercenaries[mercIndex] };
    let affinityGain = 3; // Default for resources/consumables
    let staminaGain = 0;

    // Special handling for consumables
    if (itemId === 'stamina_potion') {
        staminaGain = 50;
        affinityGain = 5;
    } else if (itemId === 'affinity_debug_gift') {
        affinityGain = 50;
    } else if (inventoryItem.type === 'EQUIPMENT' && inventoryItem.equipmentData) {
        affinityGain = 5; // Base for gear
        // Rarity bonus
        switch (inventoryItem.equipmentData.rarity) {
            case EquipmentRarity.UNCOMMON: affinityGain += 2; break;
            case EquipmentRarity.RARE: affinityGain += 4; break;
            case EquipmentRarity.EPIC: affinityGain += 7; break;
            case EquipmentRarity.LEGENDARY: affinityGain += 12; break;
        }
    }

    mercenary.affinity = Math.min(100, (mercenary.affinity || 0) + affinityGain);
    if (staminaGain > 0) {
        mercenary.expeditionEnergy = Math.min(DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY, (mercenary.expeditionEnergy || 0) + staminaGain);
    }

    const newInventory = state.inventory.map(item => {
        if (item.id === itemId) {
            return { ...item, quantity: item.quantity - 1 };
        }
        return item;
    }).filter(i => i.quantity > 0);

    const newMercenaries = [...state.knownMercenaries];
    newMercenaries[mercIndex] = mercenary;

    let logMsg = `Gifted ${inventoryItem.name} to ${mercenary.name}. Affinity +${affinityGain}.`;
    if (staminaGain > 0) logMsg += ` Stamina +${staminaGain}.`;

    return {
        ...state,
        inventory: newInventory,
        knownMercenaries: newMercenaries,
        logs: [logMsg, ...state.logs]
    };
};

export const handleTalkMercenary = (state: GameState, payload: { mercenaryId: string }): GameState => {
    const { mercenaryId } = payload;
    if (state.talkedToToday.includes(mercenaryId)) return state;

    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const newMercenaries = [...state.knownMercenaries];
    const merc = { ...newMercenaries[mercIndex] };
    merc.affinity = Math.min(100, (merc.affinity || 0) + 1);
    newMercenaries[mercIndex] = merc;

    return {
        ...state,
        knownMercenaries: newMercenaries,
        talkedToToday: [...state.talkedToToday, mercenaryId],
        logs: [`Talked with ${merc.name}. Affinity +1.`, ...state.logs]
    };
};

export const handleAllocateStat = (state: GameState, payload: { mercenaryId: string; stat: keyof PrimaryStats }): GameState => {
    const { mercenaryId, stat } = payload;
    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const merc = state.knownMercenaries[mercIndex];
    const totalAllocated = merc.allocatedStats.str + merc.allocatedStats.vit + merc.allocatedStats.dex + merc.allocatedStats.int + merc.allocatedStats.luk;
    const totalPossible = (merc.level - 1) * 3;

    if (totalAllocated >= totalPossible) return state;

    const newAllocated = { ...merc.allocatedStats, [stat]: merc.allocatedStats[stat] + 1 };
    const merged = mergePrimaryStats(merc.stats, newAllocated);

    // Vitals update
    const newMaxHp = calculateMaxHp(merged, merc.level);
    const newMaxMp = calculateMaxMp(merged, merc.level);
    // Heal proportional to hp increase
    const hpGain = newMaxHp - merc.maxHp;
    const mpGain = newMaxMp - merc.maxMp;

    const updatedMerc: Mercenary = {
        ...merc,
        allocatedStats: newAllocated,
        maxHp: newMaxHp,
        currentHp: merc.currentHp + (hpGain > 0 ? hpGain : 0),
        maxMp: newMaxMp,
        currentMp: merc.currentMp + (mpGain > 0 ? mpGain : 0)
    };

    const newKnownMercenaries = [...state.knownMercenaries];
    newKnownMercenaries[mercIndex] = updatedMerc;

    return {
        ...state,
        knownMercenaries: newKnownMercenaries
    };
};

export const handleUpdateMercenaryStats = (state: GameState, payload: { mercenaryId: string; stats: PrimaryStats }): GameState => {
    const { mercenaryId, stats } = payload;
    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const merc = state.knownMercenaries[mercIndex];

    const merged = mergePrimaryStats(merc.stats, stats);
    const newMaxHp = calculateMaxHp(merged, merc.level);
    const newMaxMp = calculateMaxMp(merged, merc.level);

    // Maintain current health percentage if possible, or just add the flat difference
    const hpDiff = newMaxHp - merc.maxHp;
    const mpDiff = newMaxMp - merc.maxMp;

    const updatedMerc: Mercenary = {
        ...merc,
        allocatedStats: stats,
        maxHp: newMaxHp,
        maxMp: newMaxMp,
        currentHp: merc.currentHp + (hpDiff > 0 ? hpDiff : 0),
        currentMp: merc.currentMp + (mpDiff > 0 ? mpDiff : 0)
    };

    const newKnownMercenaries = [...state.knownMercenaries];
    newKnownMercenaries[mercIndex] = updatedMerc;

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        logs: [`Updated attributes for ${merc.name}.`, ...state.logs]
    };
};

import { GameState } from '../types/index';
import { GameAction } from './actions';

// Import Handlers
import { handleRepairWork } from './reducer/repair';
import { handleSleep, handleConfirmSleep } from './reducer/sleep';
import { handleTriggerEvent, handleCloseEvent, handleToggleJournal } from './reducer/events';
import { handleAcquireItem, handlePayCost, handleBuyMarketItems, handleInstallFurnace, handleSellItem, handleUseItem } from './reducer/inventory';
import { handleStartCrafting, handleCancelCrafting, handleFinishCrafting, handleSetCrafting, handleUpdateForgeStatus } from './reducer/crafting';
import { handleToggleShop, handleEnqueueCustomer, handleNextCustomer, handleDismissCustomer } from './reducer/shop';
import { handleAddKnownMercenary, handleScoutMercenary, handleHireMercenary, handleFireMercenary, handleAllocateStat, handleUpdateMercenaryStats, handleGiveGift, handleTalkMercenary } from './reducer/mercenary';
import { handleStartExpedition, handleCompleteExpedition, handleClaimExpedition, handleDismissDungeonResult } from './reducer/expedition';
import { handleEquipItem, handleUnequipItem } from './reducer/equipment';
import { handleStartManualDungeon, handleMoveManualDungeon, handleFinishManualDungeon, handleRescueNPC } from './reducer/manualDungeon';

export const gameReducer = (state: GameState, action: GameAction): GameState => {
  switch (action.type) {
    // Save & Load
    case 'LOAD_GAME': return action.payload;

    // Repair
    case 'REPAIR_WORK': return handleRepairWork(state);

    // Sleep
    case 'SLEEP': return handleSleep(state);
    case 'CONFIRM_SLEEP': return handleConfirmSleep(state);
    case 'CLOSE_SLEEP_MODAL': return { ...state, showSleepModal: false };

    // Events
    case 'TRIGGER_EVENT': return handleTriggerEvent(state, action.payload);
    case 'CLOSE_EVENT': return handleCloseEvent(state);
    case 'TOGGLE_JOURNAL': return handleToggleJournal(state);

    // Inventory & Market
    case 'ACQUIRE_ITEM': return handleAcquireItem(state, action.payload);
    case 'PAY_COST': return handlePayCost(state, action.payload);
    case 'BUY_MARKET_ITEMS': return handleBuyMarketItems(state, action.payload);
    case 'INSTALL_FURNACE': return handleInstallFurnace(state);
    case 'SELL_ITEM': return handleSellItem(state, action.payload);
    case 'USE_ITEM': return handleUseItem(state, action.payload);

    // Crafting
    case 'START_CRAFTING': return handleStartCrafting(state, action.payload);
    case 'CANCEL_CRAFTING': return handleCancelCrafting(state, action.payload);
    case 'FINISH_CRAFTING': return handleFinishCrafting(state, action.payload);
    case 'DISMISS_CRAFTING_RESULT': return { ...state, lastCraftedItem: null };
    case 'SET_CRAFTING': return handleSetCrafting(state, action.payload);
    case 'UPDATE_FORGE_STATUS': return handleUpdateForgeStatus(state, action.payload);

    // Shop
    case 'TOGGLE_SHOP': return handleToggleShop(state);
    case 'ENQUEUE_CUSTOMER': return handleEnqueueCustomer(state, action.payload);
    case 'NEXT_CUSTOMER': return handleNextCustomer(state);
    case 'DISMISS_CUSTOMER': return handleDismissCustomer(state);

    // Mercenaries
    case 'ADD_KNOWN_MERCENARY': return handleAddKnownMercenary(state, action.payload);
    case 'SCOUT_MERCENARY': return handleScoutMercenary(state, action.payload);
    case 'HIRE_MERCENARY': return handleHireMercenary(state, action.payload);
    case 'FIRE_MERCENARY': return handleFireMercenary(state, action.payload);
    case 'GIVE_GIFT': return handleGiveGift(state, action.payload);
    case 'TALK_MERCENARY': return handleTalkMercenary(state, action.payload);
    case 'ALLOCATE_STAT': return handleAllocateStat(state, action.payload);
    case 'UPDATE_MERCENARY_STATS': return handleUpdateMercenaryStats(state, action.payload);

    // Expedition
    case 'START_EXPEDITION': return handleStartExpedition(state, action.payload);
    case 'COMPLETE_EXPEDITION': return handleCompleteExpedition(state, action.payload);
    case 'CLAIM_EXPEDITION': return handleClaimExpedition(state, action.payload);
    case 'DISMISS_DUNGEON_RESULT': return handleDismissDungeonResult(state);

    // Equipment
    case 'EQUIP_ITEM': return handleEquipItem(state, action.payload);
    case 'UNEQUIP_ITEM': return handleUnequipItem(state, action.payload);

    // Manual Dungeon
    case 'START_MANUAL_DUNGEON': return handleStartManualDungeon(state, action.payload);
    case 'MOVE_MANUAL_DUNGEON': return handleMoveManualDungeon(state, action.payload);
    case 'FINISH_MANUAL_DUNGEON': return handleFinishManualDungeon(state);
    case 'RETREAT_MANUAL_DUNGEON': return { ...state, activeManualDungeon: null, showManualDungeonOverlay: false, logs: ['The squad retreated from the area.', ...state.logs] };
    case 'TOGGLE_MANUAL_DUNGEON_OVERLAY': return { ...state, showManualDungeonOverlay: action.payload };
    case 'RESCUE_NPC': return handleRescueNPC(state, action.payload);

    // Toast Notifications
    case 'SHOW_TOAST':
        return {
            ...state,
            toast: { message: action.payload, visible: true }
        };
    case 'HIDE_TOAST':
        return {
            ...state,
            toast: state.toast ? { ...state.toast, visible: false } : null
        };

    // UI Effects
    case 'SET_UI_EFFECT':
        return {
            ...state,
            uiEffects: {
                ...state.uiEffects,
                [action.payload.effect]: action.payload.value
            }
        };

    default:
      return state;
  }
};

import { GameState } from '../../types/index';
import { calculateDailyWage } from '../../config/contract-config';
import { DUNGEON_CONFIG } from '../../config/dungeon-config';
import { MARKET_CATALOG } from '../../data/market/index';

export const handleSleep = (state: GameState): GameState => {
    return { ...state, showSleepModal: true };
};

export const handleConfirmSleep = (state: GameState): GameState => {
    // Calculate wages for HIRED, ON_EXPEDITION, INJURED mercenaries
    const hiredMercs = state.knownMercenaries.filter(m => 
        ['HIRED', 'ON_EXPEDITION', 'INJURED'].includes(m.status)
    );
    let totalWages = 0;
    hiredMercs.forEach(merc => {
        totalWages += calculateDailyWage(merc.level, merc.job);
    });

    const nextDay = state.stats.day + 1;
    const newGold = state.stats.gold - totalWages;

    // --- Mercenary Energy Recovery ---
    const updatedMercenaries = state.knownMercenaries.map(merc => {
        if (['HIRED', 'INJURED', 'VISITOR'].includes(merc.status)) { // Only recover if not on expedition
            return {
                ...merc,
                expeditionEnergy: Math.min(DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY, (merc.expeditionEnergy || 0) + DUNGEON_CONFIG.DAILY_ENERGY_RECOVERY)
            };
        }
        return merc;
    });

    // --- Market Restock Logic ---
    const newMarketStock = { ...state.marketStock };
    MARKET_CATALOG.forEach(item => {
        const isOneTime = item.id === 'furnace' || item.id === 'workbench' || item.id.startsWith('scroll_');

        if (isOneTime) {
            // 일회성 아이템은 이미 소유했거나 해당 티어보다 높은 경우 리스톡하지 않음 (0 유지)
            const isOwnedOrUnlocked = 
                (item.id === 'furnace' && state.forge.hasFurnace) || 
                (item.id === 'workbench' && state.forge.hasWorkbench) ||
                (item.id === 'scroll_t2' && state.stats.tierLevel >= 2) ||
                (item.id === 'scroll_t3' && state.stats.tierLevel >= 3);

            if (isOwnedOrUnlocked) {
                newMarketStock[item.id] = 0;
            } else {
                newMarketStock[item.id] = item.maxStock;
            }
        } else {
            // 일반 자원 및 소모품은 매일 다시 채움
            newMarketStock[item.id] = item.maxStock;
        }
    });

    let logMsg = `Day ${nextDay} begins. Market supplies restocked. (Auto-saved)`;
    if (totalWages > 0) logMsg = `Day ${nextDay} begins. Paid ${totalWages} G in wages. (Auto-saved)`;
    if (newGold < 0) logMsg = `Day ${nextDay} begins. You are in debt! (${newGold} G). (Auto-saved)`;

    return {
        ...state,
        stats: {
            ...state.stats,
            day: nextDay,
            gold: newGold,
            energy: state.stats.maxEnergy,
            dailyFinancials: {
                incomeShop: 0,
                incomeInventory: 0,
                incomeDungeon: 0,
                incomeRepair: 0,
                expenseMarket: 0,
                expenseWages: totalWages, // Track wages spent at end of current day (processed during rest transition)
                expenseScout: 0
            },
        },
        knownMercenaries: updatedMercenaries,
        marketStock: newMarketStock,
        forge: { ...state.forge, isShopOpen: false },
        visitorsToday: [],
        talkedToToday: [],
        activeCustomer: null,
        shopQueue: [],
        isCrafting: false,
        showSleepModal: false,
        logs: [logMsg, ...state.logs],
        forgeTemperature: 0,
        lastForgeTime: Date.now(),
    };
};

