import { GameState, ManualDungeonSession, RoomType } from '../../types/game-state';
import { DUNGEONS } from '../../data/dungeons';
import { handleClaimExpedition } from './expedition';
import { TILLY_FOOTLOOSE } from '../../data/mercenaries';

const generateManualGrid = (width: number, height: number, locked: boolean, dungeonId: string, knownMercs: any[]) => {
    const grid: RoomType[][] = Array.from({ length: height }, () => Array(width).fill('EMPTY'));
    const visited: boolean[][] = Array.from({ length: height }, () => Array(width).fill(false));

    // 1. Entrance
    const startX = Math.floor(Math.random() * width);
    const startY = Math.floor(Math.random() * height);
    grid[startY][startX] = 'ENTRANCE';
    visited[startY][startX] = true;

    // 2. Boss
    let bossX, bossY;
    do {
        bossX = Math.floor(Math.random() * width);
        bossY = Math.floor(Math.random() * height);
    } while (Math.abs(bossX - startX) + Math.abs(bossY - startY) < 2);
    grid[bossY][bossX] = 'BOSS';

    // 3. Key (if locked)
    if (locked) {
        let keyX, keyY;
        do {
            keyX = Math.floor(Math.random() * width);
            keyY = Math.floor(Math.random() * height);
        } while (grid[keyY][keyX] !== 'EMPTY');
        grid[keyY][keyX] = 'KEY';
    }

    // 4. Hidden NPC (Tilly in Rat Cellar)
    if (dungeonId === 'dungeon_t1_rats' && !knownMercs.some(m => m.id === 'tilly_footloose')) {
        let npcX, npcY;
        do {
            npcX = Math.floor(Math.random() * width);
            npcY = Math.floor(Math.random() * height);
        } while (grid[npcY][npcX] !== 'EMPTY');
        grid[npcY][npcX] = 'NPC';
    }

    // 5. Random Gold Piles & Traps
    const totalTiles = width * height;
    const goldSpawnChance = 1 / totalTiles;
    const trapSpawnChance = 1 / totalTiles;

    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            if (grid[y][x] === 'EMPTY') {
                const roll = Math.random();
                if (roll < goldSpawnChance) {
                    grid[y][x] = 'GOLD';
                } else if (roll < goldSpawnChance + trapSpawnChance) {
                    grid[y][x] = 'TRAP';
                }
            }
        }
    }

    return { grid, visited, playerPos: { x: startX, y: startY } };
};

export const handleStartManualDungeon = (state: GameState, payload: { dungeonId: string, partyIds: string[] }): GameState => {
    const dungeon = DUNGEONS.find(d => d.id === payload.dungeonId);
    if (!dungeon) return state;

    const { grid, visited, playerPos } = generateManualGrid(
        dungeon.gridWidth, 
        dungeon.gridHeight, 
        !!dungeon.isBossLocked,
        dungeon.id,
        state.knownMercenaries
    );

    const session: ManualDungeonSession = {
        dungeonId: dungeon.id,
        partyIds: payload.partyIds,
        grid,
        visited,
        playerPos,
        hasKey: false,
        isBossLocked: !!dungeon.isBossLocked,
        goldCollected: 0
    };

    return {
        ...state,
        activeManualDungeon: session,
        showManualDungeonOverlay: true,
        logs: [`Squad has entered ${dungeon.name}. Tread carefully.`, ...state.logs]
    };
};

export const handleMoveManualDungeon = (state: GameState, payload: { x: number, y: number }): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return state;

    const newX = session.playerPos.x + payload.x;
    const newY = session.playerPos.y + payload.y;

    if (newX < 0 || newX >= dungeon.gridWidth || newY < 0 || newY >= dungeon.gridHeight) return state;

    const targetRoom = session.grid[newY][newX];
    const cost = targetRoom === 'BOSS' ? dungeon.bossEnergy : dungeon.moveEnergy;

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    const canMove = party.every(m => (m.expeditionEnergy || 0) >= cost);

    if (!canMove) {
        return {
            ...state,
            logs: [`Your squad is too exhausted to move.`, ...state.logs]
        };
    }

    if (targetRoom === 'BOSS' && session.isBossLocked && !session.hasKey) {
        return {
            ...state,
            logs: [`The Boss chamber is sealed. You need a key.`, ...state.logs]
        };
    }

    let updatedMercs = state.knownMercenaries.map(m => {
        if (session.partyIds.includes(m.id)) {
            let nextEnergy = Math.max(0, (m.expeditionEnergy || 0) - cost);
            let nextHp = m.currentHp;

            // Trap Logic: -25 HP to everyone in the party
            if (targetRoom === 'TRAP') {
                nextHp = Math.max(0, m.currentHp - 25);
            }

            return { ...m, expeditionEnergy: nextEnergy, currentHp: nextHp };
        }
        return m;
    });

    const newVisited = [...session.visited.map(row => [...row])];
    newVisited[newY][newX] = true;

    // Grid modification logic
    let extraGold = 0;
    let newGrid = [...session.grid.map(row => [...row])];
    let logMsg = '';

    if (targetRoom === 'GOLD') {
        const tier = dungeon.tier || 1;
        const roll = Math.random();

        if (roll < 0.65) {
            extraGold = tier * 25;
            logMsg = `Looted a small pouch of gold! (+${extraGold} G)`;
        } else if (roll < 0.90) {
            extraGold = tier * 50;
            logMsg = `Found a stash of coins! (+${extraGold} G)`;
        } else {
            extraGold = tier * 75;
            logMsg = `Discovered an ancient gold cache! (+${extraGold} G)`;
        }

        newGrid[newY][newX] = 'EMPTY';
    } else if (targetRoom === 'TRAP') {
        logMsg = `IT'S A TRAP! The squad took heavy damage. (-25 HP)`;
        // Traps persist, so we don't change newGrid[newY][newX] to 'EMPTY'
    } else if (targetRoom === 'KEY') {
        logMsg = `Found a rusted key!`;
    } else if (targetRoom === 'NPC' && !session.npcFound) {
        logMsg = `Spotted a survivor hiding in the shadows!`;
    }

    const newSession: ManualDungeonSession = {
        ...session,
        grid: newGrid,
        playerPos: { x: newX, y: newY },
        visited: newVisited,
        hasKey: targetRoom === 'KEY' ? true : session.hasKey,
        goldCollected: session.goldCollected + extraGold
    };

    return {
        ...state,
        knownMercenaries: updatedMercs,
        activeManualDungeon: newSession,
        logs: logMsg ? [logMsg, ...state.logs] : state.logs
    };
};

export const handleFinishManualDungeon = (state: GameState): GameState => {
    const session = state.activeManualDungeon;
    if (!session) return state;

    const dungeonDef = DUNGEONS.find(d => d.id === session.dungeonId);
    const baseGold = dungeonDef?.goldReward || 0;

    const dummyExpId = `manual_clear_${Date.now()}`;
    const tempState: GameState = {
        ...state,
        activeExpeditions: [{
            id: dummyExpId,
            dungeonId: session.dungeonId,
            partyIds: session.partyIds,
            startTime: Date.now(),
            endTime: Date.now(),
            status: 'COMPLETED' as const
        }]
    };

    const finalState = handleClaimExpedition(tempState, { 
        expeditionId: dummyExpId, 
        rescuedNpcId: session.rescuedNpcId 
    });

    const totalManualGold = session.goldCollected;

    if (finalState.dungeonResult) {
        finalState.dungeonResult.goldGained = (finalState.dungeonResult.goldGained || 0) + totalManualGold;
    }

    return { 
        ...finalState, 
        stats: {
            ...finalState.stats,
            gold: finalState.stats.gold + totalManualGold,
            dailyFinancials: {
                ...finalState.stats.dailyFinancials,
                incomeDungeon: finalState.stats.dailyFinancials.incomeDungeon + totalManualGold
            }
        },
        activeManualDungeon: null, 
        showManualDungeonOverlay: false 
    };
};

export const handleRescueNPC = (state: GameState, payload: { npcId: string }): GameState => {
    if (state.knownMercenaries.some(m => m.id === payload.npcId)) return state;
    if (state.activeManualDungeon?.rescuedNpcId === payload.npcId) return state;

    const newSession = state.activeManualDungeon ? {
        ...state.activeManualDungeon,
        npcFound: true,
        rescuedNpcId: payload.npcId
    } : null;

    return {
        ...state,
        activeManualDungeon: newSession,
        logs: [`Rescue initiated for survivor. Secure the objective to escort them out.`, ...state.logs]
    };
};

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';
import { ManualDungeonSession, RoomType } from '../types/game-state';

export interface DungeonSceneData {
    session: ManualDungeonSession;
    moveEnergy: number;
    bossEnergy: number;
    onMove: (dx: number, dy: number) => void;
}

export default class DungeonScene extends Phaser.Scene {
    public add!: Phaser.GameObjects.GameObjectFactory;
    public tweens!: Phaser.Tweens.TweenManager;
    public scale!: Phaser.Scale.ScaleManager;
    public cameras!: Phaser.Cameras.Scene2D.CameraManager;
    public input!: Phaser.Input.InputPlugin;
    public time!: Phaser.Time.Clock;
    public events!: Phaser.Events.EventEmitter;
    public load!: Phaser.Loader.LoaderPlugin;
    public textures!: Phaser.Textures.TextureManager;
    public anims!: Phaser.Animations.AnimationManager;

    private session!: ManualDungeonSession;
    private onMoveCallback!: (dx: number, dy: number) => void;

    private root!: Phaser.GameObjects.Container;
    private mapLayer!: Phaser.GameObjects.Container;
    private contentLayer!: Phaser.GameObjects.Container;
    private playerLayer!: Phaser.GameObjects.Container;

    private playerMarker!: Phaser.GameObjects.Container;
    private revealedTiles: Set<string> = new Set();
    private contentByCoord: Map<string, Phaser.GameObjects.Text> = new Map();

    private sprayEmitter!: Phaser.GameObjects.Particles.ParticleEmitter;

    private tileWidth = 84;
    private tileGap = 8;
    private isMoving = false;

    // 드래그 관련 변수
    private isDragging = false;
    private dragStartX = 0;
    private dragStartY = 0;

    constructor() {
        super('DungeonScene');
    }

    init(data: DungeonSceneData) {
        this.session = data.session;
        this.onMoveCallback = data.onMove;
    }

    preload() {
        this.load.image('sparkle', getAssetUrl('particle_spark1.png'));
    }

    create() {
        this.cameras.main.setBackgroundColor(0x000000);

        this.root = this.add.container(0, 0);

        this.mapLayer = this.add.container(0, 0);
        this.contentLayer = this.add.container(0, 0);
        this.playerLayer = this.add.container(0, 0);

        this.root.add([this.mapLayer, this.contentLayer, this.playerLayer]);

        // 스프레이 입자 설정
        this.sprayEmitter = this.add.particles(0, 0, 'sparkle', {
            speed: { min: 60, max: 140 },
            scale: { start: 0.6, end: 0 },
            alpha: { start: 1, end: 0 },
            lifespan: 800,
            gravityY: 80,
            blendMode: 'ADD',
            emitting: false
        });
        this.root.add(this.sprayEmitter);

        this.initialRender();
        this.createPlayer();
        this.alignViewToEntrance();

        this.scale.on('resize', () => this.alignViewToEntrance(), this);
        this.setupDragControls();
    }

    private setupDragControls() {
        this.input.on('pointerdown', (pointer: Phaser.Input.Pointer) => {
            this.isDragging = true;
            this.dragStartX = pointer.x - this.root.x;
            this.dragStartY = pointer.y - this.root.y;
        });

        this.input.on('pointermove', (pointer: Phaser.Input.Pointer) => {
            if (!this.isDragging) return;
            this.root.setPosition(pointer.x - this.dragStartX, pointer.y - this.dragStartY);
        });

        this.input.on('pointerup', () => {
            this.isDragging = false;
        });

        this.input.on('pointerout', () => {
            this.isDragging = false;
        });
    }

    private initialRender() {
        const { grid, visited } = this.session;
        const rows = grid.length;
        const cols = grid[0].length;

        this.mapLayer.removeAll(true);
        this.contentLayer.removeAll(true);
        this.revealedTiles.clear();
        this.contentByCoord.clear();

        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                if (visited[y][x]) {
                    this.drawRevealedTile(x, y, grid[y][x], false);
                }
            }
        }
    }

    private drawRevealedTile(x: number, y: number, type: RoomType, animate: boolean) {
        const key = `${x},${y}`;
        const tx = x * (this.tileWidth + this.tileGap);
        const ty = y * (this.tileWidth + this.tileGap);

        if (!this.revealedTiles.has(key)) {
            // 바닥 타일
            const tile = this.add.rectangle(tx, ty, this.tileWidth, this.tileWidth, 0x1c1917)
                .setStrokeStyle(2, 0x44403c)
                .setOrigin(0.5);
            this.mapLayer.add(tile);

            if (animate) {
                this.sprayEmitter.emitParticleAt(tx, ty, 15);
                tile.setAlpha(0).setScale(0.7);
                this.tweens.add({
                    targets: tile,
                    alpha: 1,
                    scale: 1,
                    duration: 600,
                    ease: 'Back.easeOut'
                });
            }
            this.revealedTiles.add(key);
        }

        // 콘텐츠 갱신
        if (this.contentByCoord.has(key)) {
            this.contentByCoord.get(key)!.destroy();
        }
        const content = this.createRoomContents(type, tx, ty);
        if (content) {
            this.contentByCoord.set(key, content);
            if (animate) {
                content.setAlpha(0).setScale(0.5);
                this.tweens.add({
                    targets: content,
                    alpha: 1,
                    scale: 1,
                    duration: 500,
                    delay: 200,
                    ease: 'Cubic.easeOut'
                });
            }
        }
    }

    private createRoomContents(type: RoomType, x: number, y: number) {
        let content: Phaser.GameObjects.Text | null = null;
        switch (type) {
            case 'BOSS':
                content = this.add.text(x, y, '💀', { fontSize: '32px' }).setOrigin(0.5);
                if (this.session.isBossLocked && !this.session.hasKey) content.setAlpha(0.3);
                break;
            case 'KEY':
                content = this.add.text(x, y, '🔑', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'ENTRANCE':
                content = this.add.text(x, y, '🚪', { fontSize: '28px' }).setOrigin(0.5);
                break;
            case 'GOLD':
                content = this.add.text(x, y, '💰', { fontSize: '28px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    y: y - 5,
                    duration: 1200,
                    yoyo: true,
                    repeat: -1,
                    ease: 'Sine.easeInOut'
                });
                break;
            case 'TRAP':
                content = this.add.text(x, y, '🕸️', { fontSize: '28px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    angle: 15,
                    duration: 500,
                    yoyo: true,
                    repeat: -1,
                    ease: 'Sine.easeInOut'
                });
                break;
            case 'NPC':
                content = this.add.text(x, y, '👤', { fontSize: '30px' }).setOrigin(0.5);
                this.tweens.add({
                    targets: content,
                    alpha: 0.5,
                    duration: 1000,
                    yoyo: true,
                    repeat: -1
                });
                break;
        }
        if (content) {
            this.contentLayer.add(content);
        }
        return content;
    }

    private createPlayer() {
        const { x, y } = this.session.playerPos;
        const px = x * (this.tileWidth + this.tileGap);
        const py = y * (this.tileWidth + this.tileGap);

        const visual = this.add.container(0, 0);
        const circle = this.add.circle(0, 0, 26, 0x6366f1, 0.9).setStrokeStyle(3, 0xffffff);
        const icon = this.add.text(0, 0, '👤', { fontSize: '24px' }).setOrigin(0.5);
        visual.add([circle, icon]);

        this.playerMarker = this.add.container(px, py, [visual]);
        this.playerLayer.add(this.playerMarker);

        this.tweens.add({
            targets: visual,
            y: -8,
            duration: 800,
            yoyo: true,
            repeat: -1,
            ease: 'Sine.easeInOut'
        });
    }

    private alignViewToEntrance() {
        const { width, height } = this.scale;
        const { x, y } = this.session.playerPos;

        const yOffset = -height * 0.15;
        const currentScale = 1.0;
        this.root.setScale(currentScale);

        const targetX = x * (this.tileWidth + this.tileGap);
        const targetY = y * (this.tileWidth + this.tileGap);

        this.root.setPosition((width / 2) - (targetX * currentScale), (height / 2 + yOffset) - (targetY * currentScale));
    }

    public updateSession(newSession: ManualDungeonSession) {
        this.session = newSession;
        const { x, y } = newSession.playerPos;
        const targetLocalX = x * (this.tileWidth + this.tileGap);
        const targetLocalY = y * (this.tileWidth + this.tileGap);

        this.isMoving = true;

        this.tweens.add({
            targets: this.playerMarker,
            x: targetLocalX,
            y: targetLocalY,
            duration: 300,
            ease: 'Cubic.out',
            onComplete: () => {
                this.isMoving = false;
                this.drawRevealedTile(x, y, newSession.grid[y][x], true);
            }
        });
    }

    public move(dx: number, dy: number) {
        if (this.isMoving) return;
        this.onMoveCallback(dx, dy);
    }
}

import React, { useEffect, useRef, useState, useMemo } from 'react';
import Phaser from 'phaser';
import { useGame } from '../../../context/GameContext';
import { DUNGEONS } from '../../../data/dungeons';
import DungeonScene from '../../../game/DungeonScene';
import DialogueBox from '../../DialogueBox';
import { 
    Key, Zap, LogOut, X, Save, Trophy, Heart, Sparkles, Coins
} from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';
import { getAssetUrl } from '../../../utils';

const AssaultNavigator = () => {
    const { state, actions } = useGame();
    const session = state.activeManualDungeon;
    const gameRef = useRef<Phaser.Game | null>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isReady, setIsReady] = useState(false);
    const [showAbortConfirm, setShowAbortConfirm] = useState(false);
    const [isEnding, setIsEnding] = useState(false);

    // Persistent tactical feedback
    const [lastDiscoveryMessage, setLastDiscoveryMessage] = useState<string>('');

    // Rescue interaction state
    const [rescueStep, setRescueStep] = useState<'NONE' | 'DIALOGUE' | 'DONE'>('NONE');

    if (!session) return null;

    const dungeon = DUNGEONS.find(d => d.id === session.dungeonId);
    if (!dungeon) return null;

    const party = state.knownMercenaries.filter(m => session.partyIds.includes(m.id));
    const avgEnergy = party.reduce((sum, m) => sum + (m.expeditionEnergy || 0), 0) / (party.length || 1);

    const currentRoomType = session.grid[session.playerPos.y][session.playerPos.x];
    const isNPCNode = currentRoomType === 'NPC';
    const isEntranceNode = currentRoomType === 'ENTRANCE';

    useEffect(() => {
        const checkSize = () => {
            if (containerRef.current && containerRef.current.clientWidth > 0) {
                setIsReady(true);
            } else {
                requestAnimationFrame(checkSize);
            }
        };
        checkSize();
    }, []);

    // Monitor room entries for persistent discovery messages
    useEffect(() => {
        const room = session.grid[session.playerPos.y][session.playerPos.x];
        if (room === 'KEY') {
            setLastDiscoveryMessage("Chamber key recovered. Tactical scanning identifies the Boss location.");
        } else if (room === 'NPC' && !session.npcFound) {
            setLastDiscoveryMessage("Life-sign confirmed. Survivor location secured. Initializing escort protocols.");
        } else if (room === 'BOSS') {
            setLastDiscoveryMessage("Enemy High-Value Target neutralized. Area lockdown lifted. Sector secured.");
        } else if (room === 'TRAP') {
            setLastDiscoveryMessage("WARNING: Trap triggered! Structural integrity of squad units compromised.");
        } else if (isEntranceNode && lastDiscoveryMessage === '') {
            setLastDiscoveryMessage(`Infiltration of ${dungeon.name} successful. Commencing area sweep.`);
        }
    }, [session.playerPos, session.grid, session.npcFound, dungeon.name, isEntranceNode]);

    useEffect(() => {
        if (!isReady || !containerRef.current) return;

        if (!gameRef.current) {
            const config: Phaser.Types.Core.GameConfig = {
                type: Phaser.AUTO,
                parent: containerRef.current,
                width: containerRef.current.clientWidth,
                height: containerRef.current.clientHeight,
                backgroundColor: 'transparent',
                transparent: true,
                scene: [DungeonScene],
                scale: {
                    mode: Phaser.Scale.RESIZE,
                    autoCenter: Phaser.Scale.CENTER_BOTH
                }
            };

            const game = new Phaser.Game(config);
            gameRef.current = game;

            game.scene.start('DungeonScene', {
                session,
                moveEnergy: dungeon.moveEnergy,
                bossEnergy: dungeon.bossEnergy,
                onMove: (dx: number, dy: number) => {
                    actions.moveInManualDungeon(dx, dy);
                }
            });
        } else {
            const scene = gameRef.current.scene.getScene('DungeonScene') as DungeonScene;
            if (scene) scene.updateSession(session);
        }
    }, [isReady, session, actions, dungeon.moveEnergy, dungeon.bossEnergy]);

    useEffect(() => {
        if (isEnding) return;
        const { x, y } = session.playerPos;
        const currentRoom = session.grid[y][x];

        if (currentRoom === 'BOSS') {
            setIsEnding(true);
        }
    }, [session.playerPos, session.grid, isEnding]);

    useEffect(() => {
        return () => {
            if (gameRef.current) {
                gameRef.current.destroy(true);
                gameRef.current = null;
            }
        };
    }, []);

    const handleDpadMove = (dx: number, dy: number) => {
        if (isEnding || rescueStep === 'DIALOGUE') return;
        const scene = gameRef.current?.scene.getScene('DungeonScene') as DungeonScene;
        if (scene) scene.move(dx, dy);
    };

    const handleClose = () => {
        if (isEnding) return;
        actions.toggleManualDungeonOverlay(false);
    };

    const handleAbort = () => {
        actions.retreatFromManualDungeon();
        setShowAbortConfirm(false);
    };

    const handleRescueClick = () => {
        setRescueStep('DIALOGUE');
    };

    const handleRescueConfirm = () => {
        if (session.dungeonId === 'dungeon_t1_rats') {
            actions.rescueMercenary('tilly_footloose');
        }
        setRescueStep('DONE');
    };

    const navOptions = useMemo(() => {
        if (rescueStep === 'DIALOGUE') {
            return [
                { label: "Accept Escort Request", action: handleRescueConfirm, variant: 'primary' as const }
            ];
        }

        const baseOptions = [
            { 
                label: "North", 
                action: () => handleDpadMove(0, -1), 
                disabled: session.playerPos.y <= 0 
            },
            { 
                label: "South", 
                action: () => handleDpadMove(0, 1), 
                disabled: session.playerPos.y >= dungeon.gridHeight - 1 
            },
            { 
                label: "West", 
                action: () => handleDpadMove(-1, 0), 
                disabled: session.playerPos.x <= 0 
            },
            { 
                label: "East", 
                action: () => handleDpadMove(1, 0), 
                disabled: session.playerPos.x >= dungeon.gridWidth - 1 
            },
        ];

        if (isNPCNode && !session.npcFound && rescueStep === 'NONE') {
            return [
                { label: "Rescue Survivor", action: handleRescueClick, variant: 'primary' as const },
                ...baseOptions
            ];
        }

        return baseOptions;
    }, [session.playerPos, dungeon, isEnding, isNPCNode, session.npcFound, rescueStep]);

    const tacticalDialogue = useMemo(() => {
        if (isEnding) return "Area secured. Sector lockdown lifted. Preparing for tactical extraction and loot inventory...";

        if (rescueStep === 'DIALOGUE') {
            return "Oh! Thank the gods! I thought the rats would have me for sure. Please, lead the way out... I'll find my own way back once we're clear of this floor.";
        }

        if (isNPCNode && !session.npcFound) return "Warning: Unidentified life-sign detected in the immediate vicinity. Civilian presence confirmed. Escort protocols advised.";

        // Context-aware objectives
        let nextObjective = "";
        const isLowHp = party.some(m => m.currentHp < m.maxHp * 0.25);

        if (isLowHp) {
            nextObjective = "MEDICAL EMERGENCY: Multiple units at critical HP. Proceed with extreme caution.";
        } else if (avgEnergy < 15) {
            nextObjective = "FATIGUE CRITICAL: Squad performance degraded. Secure exit immediately.";
        } else if (session.isBossLocked && !session.hasKey) {
            nextObjective = "Next Action: Sweep sector for rusted chamber key. Boss room remains inaccessible.";
        } else if (session.hasKey) {
            nextObjective = "Next Action: Sector key secured. Proceed to the inner sanctum to neutralize the Boss.";
        } else if (session.npcFound) {
            nextObjective = "Next Action: Civilian secured. Proceed to Boss elimination to ensure safe passage.";
        } else {
            nextObjective = "Next Action: Sweep floor for valuables and chamber key. Watch for hazards.";
        }

        // Return combined discovery + next step
        return `${lastDiscoveryMessage || "Scanning sector..."}\n\n[ ${nextObjective} ]`;
    }, [avgEnergy, session.hasKey, isEnding, isNPCNode, session.npcFound, rescueStep, lastDiscoveryMessage, session.isBossLocked, party]);

    const speakerName = useMemo(() => {
        if (isEnding) return "Tactical AI";
        if (rescueStep === 'DIALOGUE') return "Tilly Footloose";
        return "Tactical Link";
    }, [isEnding, rescueStep]);

    return (
        <div className="absolute inset-0 z-[100] bg-stone-950 flex flex-col animate-in fade-in duration-500 overflow-hidden">

            {/* Phaser Viewport - Fullscreen Backdrop */}
            <div ref={containerRef} className="absolute inset-0 z-0" />

            {/* NPC Visual Exposure Layer */}
            {rescueStep === 'DIALOGUE' && (
                <div className="absolute inset-0 z-30 flex flex-col items-center justify-end pointer-events-none pb-0 animate-in fade-in zoom-in-95 duration-700">
                    <div className="relative h-[65dvh] md:h-[85dvh] flex justify-center bottom-[20dvh] md:bottom-[10dvh]">
                        <img 
                            src={getAssetUrl('tily_footloose.png')} 
                            alt="Rescued Survivor"
                            className="h-full w-auto object-contain object-bottom filter drop-shadow-[0_0_50px_rgba(0,0,0,1)]"
                        />
                        <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-64 h-8 bg-black/60 blur-3xl rounded-full -z-10"></div>
                    </div>
                </div>
            )}

            {/* Top Bar */}
            <div className="relative p-2 md:p-4 bg-stone-950/20 backdrop-blur-md border-b border-white/10 flex justify-between items-center shrink-0 z-50 gap-2">
                <div className="flex items-center gap-2 md:gap-4 min-w-0">
                    <div className={`w-10 h-10 md:w-12 md:h-12 rounded-xl border flex items-center justify-center shrink-0 transition-all ${session.hasKey ? 'bg-amber-900/40 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.4)] animate-pulse' : 'bg-stone-950/50 border-stone-800'}`}>
                        <Key className={`w-5 h-5 md:w-7 md:h-7 ${session.hasKey ? 'text-amber-400' : 'text-stone-600'}`} />
                    </div>
                    <div className="min-w-0">
                        <h2 className="text-stone-100 font-black uppercase text-xs md:text-lg leading-none drop-shadow-md truncate">{dungeon.name}</h2>
                        <div className="flex items-center gap-2 mt-1">
                             <div className="flex items-center gap-1 bg-stone-950/60 px-1.5 py-0.5 rounded border border-white/5 shrink-0">
                                <Zap className="w-2.5 h-2.5 text-blue-500" />
                                <span className="text-[8px] md:text-[10px] font-mono font-bold text-blue-400 uppercase tracking-tighter">{Math.floor(avgEnergy)}%</span>
                             </div>
                             {session.goldCollected > 0 && (
                                <div className="flex items-center gap-1 bg-amber-900/40 px-1.5 py-0.5 rounded border border-amber-600/30 shrink-0">
                                    <Coins className="w-2.5 h-2.5 text-amber-400" />
                                    <span className="text-[8px] md:text-[10px] font-mono font-bold text-amber-200 uppercase tracking-tighter">+{session.goldCollected}</span>
                                </div>
                             )}
                             {session.npcFound && (
                                <div className="flex items-center gap-1 bg-amber-950/60 px-1.5 py-0.5 rounded border border-amber-500/20 shrink-0 animate-pulse">
                                    <Sparkles className="w-2.5 h-2.5 text-amber-500" />
                                    <span className="text-[8px] md:text-[10px] font-black text-amber-400 uppercase">Rescued</span>
                                </div>
                             )}
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-1 md:gap-2 shrink-0">
                    <button 
                        onClick={() => !isEnding && setShowAbortConfirm(true)}
                        disabled={isEnding}
                        className={`flex items-center gap-1 md:gap-2 px-2 md:px-3 py-1.5 md:py-2 bg-red-950/40 hover:bg-red-900/60 border border-red-900/50 rounded-lg text-red-400 font-bold text-[9px] md:text-[10px] transition-all backdrop-blur-md ${isEnding ? 'opacity-30 cursor-not-allowed' : ''}`}
                    >
                        <LogOut className="w-3 h-3 md:w-3.5 md:h-3.5" /> <span className="hidden xs:inline">Abort</span>
                    </button>
                    <button 
                        onClick={handleClose}
                        disabled={isEnding}
                        className={`flex items-center gap-1 md:gap-2 px-2 md:px-4 py-1.5 md:py-2 bg-stone-800/60 hover:bg-stone-700/80 border border-white/10 rounded-lg text-stone-200 font-bold text-[9px] md:text-xs transition-all backdrop-blur-md ${isEnding ? 'opacity-30 cursor-not-allowed' : ''}`}
                    >
                        <X className="w-3 h-3 md:w-4 md:h-4" /> <span>Pause</span>
                    </button>
                </div>
            </div>

            <div className="flex-1 pointer-events-none" />

            <div className="relative z-40">
                <DialogueBox 
                    speaker={speakerName}
                    text={tacticalDialogue}
                    options={isEnding ? [] : (navOptions as any)}
                />
            </div>

            <ConfirmationModal 
                isOpen={showAbortConfirm}
                title="Abandon Assault?"
                message="Retreating will forfeit all progress in this floor. All spent energy will not be recovered."
                confirmLabel="Confirm Retreat"
                cancelLabel="Stay Focused"
                isDanger={true}
                onConfirm={handleAbort}
                onCancel={() => setShowAbortConfirm(false)}
            />

            {/* 승리 오버레이 */}
            {isEnding && (
                <div 
                    className="absolute inset-0 z-[60] bg-black/40 backdrop-blur-[2px] flex flex-col items-center justify-center animate-in fade-in duration-500 pointer-events-auto cursor-pointer"
                    onClick={actions.finishManualAssault}
                >
                    <div className="bg-amber-600 text-white px-8 py-4 rounded-2xl shadow-[0_0_50px_rgba(217,119,6,0.6)] animate-in zoom-in-95 duration-300 flex items-center gap-3 mb-4">
                        <Trophy className="w-8 h-8 text-white animate-bounce" />
                        <span className="text-2xl font-black italic tracking-tighter uppercase">Objective Complete!</span>
                    </div>
                    <div className="text-amber-200/60 text-[10px] md:text-xs font-black uppercase tracking-[0.3em] animate-pulse">
                        Touch to Claim Rewards
                    </div>
                </div>
            )}
        </div>
    );
};

export default AssaultNavigator;

import React, { useEffect, useRef, useState, useMemo } from 'react';
