  | { type: 'COMPLETE_EXPEDITION'; payload: { expeditionId: string } }
  | { type: 'CLAIM_EXPEDITION'; payload: { expeditionId: string } }
  | { type: 'ABORT_EXPEDITION'; payload: { expeditionId: string } }
